      batchStatsData.forEach(item => {
          const imported = item.productInfo?.totalImported || 0;
          const balance = imported - item.qtyOrdered;
          text += `${item.name}: ${item.qtyOrdered} | ${imported} | ${balance > 0 ? '+' : ''}${balance}\n`;
      });
