  const contactActions = {
      call: (phone: string) => window.open(`tel:${phone}`, '_self'),
      zalo: (phone: string) => window.open(`https://zalo.me/${normalizePhone(phone).replace(/^0/, '84')}`, '_blank'),
      sms: (phone: string) => window.open(`sms:${phone}`, '_self'),
