                              <i className={`fas ${isGettingLocation ? 'fa-circle-notch fa-spin' : 'fa-map-marker-alt'}`}></i>
                          </button>
                      </div>
                  </div>
                  {formData.isAddressVerified && (
                      <div className="md:col-span-2 text-[10px] text-green-600 font-bold flex items-center gap-1">
                          <i className="fas fa-check-circle"></i> Đã ghim toạ độ chính xác từ GPS
