                  return prev.filter(s => s !== statusValue); 
              } 
              return [...prev, statusValue]; 
          }); 
      } 
      if (type === 'BATCH') { 
          const batchValue = String(value); 
          setFilterBatch(prev => { 
              if (prev.includes(batchValue)) { 
                  return prev.filter(b => b !== batchValue); 
              } 
              return [...prev, batchValue]; 
          }); 
      } 
