    // --- CHỨC NĂNG IN TEM 8 TEM/A4 (ĐÃ THAY ÁO MỚI) ---
    generateInvoiceBatch: async (orders: Order[], batchName: string) => {
        const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
        const fontBase64 = await fetchFont();
        let fontName = 'helvetica';

        if (fontBase64) {
            doc.addFileToVFS('Roboto.ttf', fontBase64);
            doc.addFont('Roboto.ttf', 'Roboto', 'normal');
            doc.addFont('Roboto.ttf', 'Roboto', 'bold');
            doc.addFont('Roboto.ttf', 'Roboto', 'italic');
            doc.setFont('Roboto');
            fontName = 'Roboto';
        }

        const shopConfig = await storageService.getShopConfig();
        const shopName = (shopConfig?.shopName || 'ECOGO STORE').toUpperCase();

        const labelW = 100;
        const labelH = 70; // 4 rows * 70 = 280mm (A4 height 297mm)
        const marginX = 5;
        const marginY = 8;

        let col = 0;
        let row = 0;

        for (let i = 0; i < orders.length; i++) {
            const order = orders[i];

            // Calculate Position
            const x = marginX + (col * labelW);
            const y = marginY + (row * labelH);

            // ---------------------------------------------------------
            // 1. OUTER BORDER (Viền ngoài)
            // ---------------------------------------------------------
            doc.setDrawColor(0);
            doc.setLineWidth(0.2);
            doc.rect(x, y, labelW, labelH);

            // ---------------------------------------------------------
            // 2. HEADER SECTION (Định danh)
            // ---------------------------------------------------------
            // Left: Shop Info & Date
            doc.setFontSize(8);
            doc.setFont(fontName, 'bold');
            doc.text(shopName, x + 4, y + 6);

            doc.setFontSize(7);
            doc.setFont(fontName, 'normal');
            const dateStr = new Date(order.createdAt).toLocaleDateString('vi-VN');
            doc.text(`Ngày: ${dateStr}`, x + 4, y + 10);

            // Right: Order ID (HUGE & BOLD)
            doc.setFontSize(14);
            doc.setFont(fontName, 'bold');
            doc.text(`#${order.id}`, x + labelW - 4, y + 9, { align: 'right' });

            // BOLD SEPARATOR LINE
            doc.setLineWidth(0.5);
            doc.line(x + 2, y + 13, x + labelW - 2, y + 13);

            // ---------------------------------------------------------
            // 3. BODY SECTION (Thông tin giao hàng)
            // ---------------------------------------------------------
            let cursorY = y + 20;

            // CUSTOMER NAME & PHONE (Same line, Large)
            doc.setFontSize(11);
            doc.setFont(fontName, 'bold');
            const customerInfo = `${order.customerName} - ${order.customerPhone}`;
            const customerLines = doc.splitTextToSize(customerInfo, labelW - 8);
            doc.text(customerLines, x + 4, cursorY);
            cursorY += (customerLines.length * 5) + 1;

            // ADDRESS (Normal font, multiline)
            doc.setFontSize(9);
            doc.setFont(fontName, 'normal');
            const addrLines = doc.splitTextToSize(order.address, labelW - 8);
            // Limit address to 3 lines to save space, add ellipsis if needed
            const displayAddr = addrLines.length > 3 ? addrLines.slice(0, 3) : addrLines;
            if (addrLines.length > 3) displayAddr[2] += '...';

            doc.text(displayAddr, x + 4, cursorY);
            cursorY += (displayAddr.length * 4) + 3;

            // LIGHT SEPARATOR (Dashed)
            doc.setLineWidth(0.1);
            doc.setLineDashPattern([1, 1], 0);
            doc.line(x + 4, cursorY, x + labelW - 4, cursorY);
            doc.setLineDashPattern([], 0);
            cursorY += 4;

            // PRODUCTS LIST
            doc.setFontSize(9);
            doc.setFont(fontName, 'bold');
            doc.text("Đơn hàng:", x + 4, cursorY);

            doc.setFont(fontName, 'normal');
            const itemsStr = order.items.map(it => `${it.name} (x${it.quantity})`).join(', ');
            const itemLines = doc.splitTextToSize(itemsStr, labelW - 25); 
            // Limit items to 3 lines
            const displayItems = itemLines.length > 3 ? itemLines.slice(0, 3) : itemLines;
            if (itemLines.length > 3) displayItems[2] += '...';

            doc.text(displayItems, x + 22, cursorY);

            // NOTE (Optional)
            if (order.notes) {
                 cursorY += (displayItems.length * 4) + 2;
                 doc.setFontSize(8);
                 doc.setFont(fontName, 'italic');
                 doc.text(`Ghi chú: ${order.notes}`, x + 4, cursorY);
            }

            // ---------------------------------------------------------
            // 4. FOOTER SECTION (Tiền & QR)
            // ---------------------------------------------------------
            const bottomY = y + labelH;

            // QR CODE (Bottom Left)
            try {
                // QR contains essential info for quick scan
                const qrText = `DH:${order.id}|${order.totalPrice}|${order.customerName}`;
                const qrData = await generateQRCode(qrText);
                if (qrData) {
                    doc.addImage(qrData, 'PNG', x + 3, bottomY - 18, 16, 16);
                }
            } catch {}

            // COD AMOUNT (Bottom Right)
            const isCOD = order.paymentMethod === 'CASH';

            if (isCOD) {
                doc.setFontSize(9);
                doc.setFont(fontName, 'normal');
                doc.text("Tổng thu người nhận:", x + labelW - 4, bottomY - 14, { align: 'right' });

                // HUGE PRICE
                doc.setFontSize(18); 
                doc.setFont(fontName, 'bold');
                doc.text(`${new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ`, x + labelW - 4, bottomY - 5, { align: 'right' });
            } else {
                // "KHÔNG THU" BOX (Clear visual indicator)
                doc.setDrawColor(0);
                doc.setLineWidth(0.5);
                doc.rect(x + labelW - 40, bottomY - 15, 36, 11); // Box rectangle

