// --- FONT CACHING & LOADING ---
// Lưu cache font để không phải tải lại mỗi lần in
const fontCache: Record<string, string> = {};

const loadFonts = async (doc: jsPDF) => {
    // Chúng ta cần tải riêng file font Medium để hiển thị Bold chuẩn xác nhất
    const fonts = [
        { url: 'https://cdnjs.cloudflare.com/ajax/libs/pdfmake/0.2.7/fonts/Roboto/Roboto-Regular.ttf', name: 'Roboto-Regular.ttf', style: 'normal' },
        { url: 'https://cdnjs.cloudflare.com/ajax/libs/pdfmake/0.2.7/fonts/Roboto/Roboto-Medium.ttf', name: 'Roboto-Medium.ttf', style: 'bold' },
        { url: 'https://cdnjs.cloudflare.com/ajax/libs/pdfmake/0.2.7/fonts/Roboto/Roboto-Italic.ttf', name: 'Roboto-Italic.ttf', style: 'italic' }
    ];

    for (const f of fonts) {
        if (!fontCache[f.name]) {
            try {
                const resp = await fetch(f.url);
                const blob = await resp.blob();
                const reader = new FileReader();
                await new Promise((resolve) => {
                    reader.onloadend = () => {
                        const res = reader.result as string;
                        // Remove data:application/octet-stream;base64, prefix
                        fontCache[f.name] = res.split(',')[1];
                        resolve(true);
                    };
                    reader.readAsDataURL(blob);
                });
            } catch (e) { console.error('Font load error', e); }
        }
        if (fontCache[f.name]) {
            doc.addFileToVFS(f.name, fontCache[f.name]);
            doc.addFont(f.name, 'Roboto', f.style);
        }
    }
    // Set default font
    doc.setFont('Roboto', 'normal');
};

// --- HELPER GRAPHICS ---
const drawPointingHand = (doc: jsPDF, x: number, y: number, size: number) => {
    // Vẽ tay chỉ (Vector)
    doc.setFillColor(0); // Màu đen

    // Ngón trỏ (chỉ sang trái)
    doc.roundedRect(x, y + size * 0.4, size * 0.5, size * 0.25, size * 0.1, size * 0.1, 'F');

    // Nắm tay
    doc.roundedRect(x + size * 0.4, y + size * 0.25, size * 0.5, size * 0.55, size * 0.15, size * 0.15, 'F');

    // Ngón cái (giơ lên một chút)
    doc.roundedRect(x + size * 0.4, y, size * 0.2, size * 0.4, size * 0.1, size * 0.1, 'F');

    // Cổ tay/Tay áo
    doc.rect(x + size * 0.8, y + size * 0.25, size * 0.4, size * 0.55, 'F');
};

