            doc.text(`${i + 1}/${orders.length}`, pX, pY + 3);

            // Thông tin Shop & Ngày
            doc.setTextColor(0, 0, 0); // Trả lại màu đen
            doc.setFontSize(8);
            doc.setFont('Roboto', 'bold');
            // Căn giữa shop name
            const dateStr = new Date(order.createdAt).toLocaleDateString('vi-VN');
            doc.text(`${shopName} - ${dateStr}`, x + (labelW / 2), pY + 3, { align: 'center' });

            // Mã đơn hàng (Góc phải - To & Đậm)
            doc.setFontSize(14);
            doc.setFont('Roboto', 'bold');
            doc.text(`#${order.id}`, pX + contentW, pY + 5, { align: 'right' });

            // Đường kẻ phân cách Header đậm
            doc.setDrawColor(0);
            doc.setLineWidth(0.5);
            doc.line(pX, pY + 8, pX + contentW, pY + 8);

            // 3. CUSTOMER INFO (BOLD & EMPHASIZED)
            let cursorY = pY + 16;

            // Tên khách hàng (TO, IN HOA, ĐẬM)
            doc.setFontSize(12); // Tăng size
            doc.setFont('Roboto', 'bold'); // Font Medium tải về sẽ hiển thị đậm rõ
            doc.text(order.customerName.toUpperCase(), pX, cursorY);

            // Số điện thoại (TO, ĐẬM)
            const phoneW = doc.getTextWidth(order.customerName.toUpperCase());
            if (phoneW < (contentW / 2)) {
                 doc.text(` - ${order.customerPhone}`, pX + phoneW, cursorY);
                 cursorY += 6;
            } else {
                 cursorY += 5;
                 doc.text(order.customerPhone, pX, cursorY);
                 cursorY += 6;
            }

            // Địa chỉ (ĐẬM, Tự động xuống dòng)
            doc.setFontSize(10);
            doc.setFont('Roboto', 'bold'); // Đảm bảo đậm
            const addrLines = doc.splitTextToSize(order.address, contentW);
            const displayAddr = addrLines.length > 3 ? addrLines.slice(0, 3) : addrLines;
            if (addrLines.length > 3) displayAddr[2] += '...';
            doc.text(displayAddr, pX, cursorY);

            cursorY += (displayAddr.length * 5) + 3;

            // Đường kẻ phân cách mỏng
            doc.setLineWidth(0.1);
            doc.line(pX, cursorY, pX + contentW, cursorY);
            cursorY += 4;

            // 4. ITEMS LIST (Hàng hóa)
            doc.setFontSize(9);
            doc.setFont('Roboto', 'normal');

            const itemsStr = order.items.map(it => `${it.name} [SL:${it.quantity}]`).join(', ');
            const itemLines = doc.splitTextToSize(itemsStr, contentW);
            const displayItems = itemLines.length > 4 ? itemLines.slice(0, 4) : itemLines;
            if (itemLines.length > 4) displayItems[3] += '...';

            doc.text(displayItems, pX, cursorY);

            // Ghi chú (nếu có)
            if (order.notes) {
                 cursorY += (displayItems.length * 4) + 2;
                 doc.setFont('Roboto', 'italic');
                 doc.setFontSize(8);
                 doc.text(`Ghi chú: ${order.notes}`, pX, cursorY);
            }

            // 5. FOOTER SECTION
            const footerY = pY + contentH - 5;

            // QR Code (Góc trái dưới) & Hand Icon
            try {
                const qrText = `DH:${order.id}|${order.totalPrice}`;
                const qrData = await generateQRCode(qrText);
                if (qrData) {
                    const qrSize = 15;
                    doc.addImage(qrData, 'PNG', pX, footerY - 13, qrSize, qrSize);

                    // Vẽ tay chỉ vào QR (sinh động, màu đen)
                    // Vị trí tay bên phải QR, chỉ sang trái
                    drawPointingHand(doc, pX + qrSize + 2, footerY - 8, 8); 

                    // Text "Quét tôi" nhỏ dưới tay
                    doc.setFontSize(6);
                    doc.setFont('Roboto', 'italic');
                    doc.text("Quét kiểm đơn", pX + qrSize + 2, footerY - 1);
                }
            } catch {}

            // Tổng tiền (Góc phải dưới - SIÊU TO)
            const isCOD = order.paymentMethod === 'CASH';

            if (isCOD) {
                doc.setFontSize(10);
