import jsPDF from 'jspdf';
import QRCode from 'qrcode';
import { Order, PaymentMethod, OrderStatus, Product } from '../types';
import { storageService, normalizeString } from './storageService';

// --- FONT CACHING & LOADING ---
const fontCache: Record<string, string> = {};

const loadFonts = async (doc: jsPDF) => {
    const fonts = [
        { url: 'https://cdnjs.cloudflare.com/ajax/libs/pdfmake/0.2.7/fonts/Roboto/Roboto-Regular.ttf', name: 'Roboto-Regular.ttf', style: 'normal' },
        { url: 'https://cdnjs.cloudflare.com/ajax/libs/pdfmake/0.2.7/fonts/Roboto/Roboto-Medium.ttf', name: 'Roboto-Medium.ttf', style: 'bold' },
        { url: 'https://cdnjs.cloudflare.com/ajax/libs/pdfmake/0.2.7/fonts/Roboto/Roboto-Italic.ttf', name: 'Roboto-Italic.ttf', style: 'italic' }
    ];

    for (const f of fonts) {
        if (!fontCache[f.name]) {
            try {
                const resp = await fetch(f.url);
                const blob = await resp.blob();
                const reader = new FileReader();
                await new Promise((resolve) => {
                    reader.onloadend = () => {
                        const res = reader.result as string;
                        fontCache[f.name] = res.split(',')[1];
                        resolve(true);
                    };
                    reader.readAsDataURL(blob);
                });
            } catch (e) { console.error('Font load error', e); }
        }
        if (fontCache[f.name]) {
            doc.addFileToVFS(f.name, fontCache[f.name]);
            doc.addFont(f.name, 'Roboto', f.style);
        }
    }
    doc.setFont('Roboto', 'normal');
};

// --- HELPER GRAPHICS ---
const drawVectorHand = (doc: jsPDF, x: number, y: number, scale: number = 1) => {
    // Vẽ tay chỉ ngón trỏ (Vector path) đẹp hơn, mềm mại hơn
    doc.setFillColor(0, 0, 0); // Màu đen

    const s = scale * 0.4; 

    // Tọa độ vẽ tay (Shape bàn tay nắm, ngón trỏ chỉ trái)
    // x, y là mũi ngón trỏ
    doc.lines([
        [12 * s, -2 * s],   // Cạnh dưới ngón trỏ
        [2 * s, 1 * s],     // Kẽ ngón giữa
        [1 * s, 3 * s],     // Đốt ngón giữa
        [3 * s, 1 * s],     // Đốt ngón áp út
        [2 * s, 3 * s],     // Đốt ngón út
        [4 * s, 0],         // Cạnh bàn tay dưới
        [0, -8 * s],        // Cổ tay lên
        [-4 * s, 0],        // Cạnh bàn tay trên
        [-2 * s, -4 * s],   // Ngón cái
        [-4 * s, 2 * s],    // Kẽ ngón cái
        [-14 * s, 0],       // Cạnh trên ngón trỏ
        [0, 4 * s],         // Đầu ngón trỏ (về lại điểm xuất phát)
    ], x + (14 * s), y, [1, 1], 'F', true); // Shift x để điểm x,y là đầu ngón trỏ
};

const generateQRCode = async (text: string): Promise<string> => {
    try {
        return await QRCode.toDataURL(text, { width: 300, margin: 0, errorCorrectionLevel: 'M' });
    } catch (e) {
        return '';
    }
};

