            ctx.textAlign = 'left'; ctx.fillStyle = '#334155'; ctx.font = 'bold 22px Arial, sans-serif'; ctx.fillText('Chi tiết đơn hàng:', leftX, textY); textY += 40;
            order.items.forEach(item => {
