import React, { useState, useEffect, useRef } from 'react';
import { storageService } from '../services/storageService';

// Ensure variable is recognized (defined in vite.config.ts)
declare const __APP_VERSION__: string;

interface Props {
  onLogin: () => void;
}

const Login: React.FC<Props> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [loading, setLoading] = useState(false);

  // Mascot States
  const [eyePosition, setEyePosition] = useState({ x: 0, y: 0 });
  const [isHappy, setIsHappy] = useState(false);
  const [isWinking, setIsWinking] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
     const lastUser = localStorage.getItem('ecogo_last_username');
     if (lastUser) setUsername(lastUser);

     // Mascot eye tracking effect
     const handleMouseMove = (e: MouseEvent) => {
        if (!containerRef.current) return;

        // Calculate position relative to the center of the screen
        const { innerWidth, innerHeight } = window;
        const x = (e.clientX - innerWidth / 2) / 30; // Reduce movement range
        const y = (e.clientY - innerHeight / 2) / 30;

        // Limit eye movement radius
        const limit = 8;
        const constrainedX = Math.max(Math.min(x, limit), -limit);
        const constrainedY = Math.max(Math.min(y, limit), -limit);

        setEyePosition({ x: constrainedX, y: constrainedY });
     };

     window.addEventListener('mousemove', handleMouseMove);
     return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  const handleMascotClick = () => {
      setIsWinking(true);
      setIsHappy(true);

      // Reset animations
      setTimeout(() => setIsWinking(false), 500);
      setTimeout(() => setIsHappy(false), 2000);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (username.trim()) {
      setLoading(true);
      setIsHappy(true); // Robot gets happy when logging in
      setTimeout(() => {
          storageService.login(username);
          localStorage.setItem('ecogo_last_username', username);
          onLogin();
      }, 1000);
    }
  };

  return (
    <div ref={containerRef} className="min-h-screen bg-gradient-to-br from-emerald-50 via-white to-blue-50 flex flex-col items-center justify-center relative overflow-hidden font-sans selection:bg-emerald-100 selection:text-emerald-900">

      {/* --- BACKGROUND BLOBS --- */}
      <div className="absolute top-[-10%] left-[-10%] w-[500px] h-[500px] bg-emerald-200/20 rounded-full blur-[80px] animate-blob mix-blend-multiply"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[500px] h-[500px] bg-blue-200/20 rounded-full blur-[80px] animate-blob animation-delay-2000 mix-blend-multiply"></div>
      <div className="absolute top-[20%] right-[20%] w-[300px] h-[300px] bg-yellow-100/30 rounded-full blur-[60px] animate-blob animation-delay-4000 mix-blend-multiply"></div>

      {/* --- MAIN CONTENT --- */}
      <div className="relative z-10 w-full max-w-sm px-4 flex flex-col items-center">

        {/* === ECOBOT MASCOT === */}
        <div 
            className={`relative w-40 h-40 mb-2 cursor-pointer transition-transform duration-300 ${isHappy ? 'scale-110' : 'hover:scale-105'}`} 
            onClick={handleMascotClick}
            title="Chạm vào tớ đi!"
        >
            {/* Float Animation Wrapper */}
            <div className={`w-full h-full animate-float ${isHappy ? 'animate-bounce-short' : ''}`}>

                {/* 1. Antenna */}
                <div className="absolute -top-6 left-1/2 -translate-x-1/2 w-1 h-8 bg-gray-300 transition-all duration-300 origin-bottom" style={{ transform: `translateX(-50%) rotate(${eyePosition.x}deg)` }}></div>
