import React, { useState, useEffect, useRef } from 'react';
import { storageService } from '../services/storageService';

// Ensure variable is recognized (defined in vite.config.ts)
declare const __APP_VERSION__: string;

interface Props {
  onLogin: () => void;
}

const Login: React.FC<Props> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [loading, setLoading] = useState(false);

  // Mascot States
  const [headRot, setHeadRot] = useState({ x: 0, y: 0 }); // Head tilt
  const [pupilPos, setPupilPos] = useState({ x: 0, y: 0 }); // Pupil movement
  const [isSleeping, setIsSleeping] = useState(false);
  const [isError, setIsError] = useState(false);
  const [isHappy, setIsHappy] = useState(false);
  const [isFocused, setIsFocused] = useState(false);

  const idleTimer = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
     const lastUser = localStorage.getItem('ecogo_last_username');
     if (lastUser) setUsername(lastUser);

     // Pre-load voices
     if ('speechSynthesis' in window) {
         window.speechSynthesis.getVoices();
     }

     const resetIdleTimer = () => {
         if (idleTimer.current) clearTimeout(idleTimer.current);
         if (isSleeping) {
             setIsSleeping(false); // Wake up!
             speak("Á! Bạn quay lại rồi.", 1.2, 1.2);
         }
         idleTimer.current = setTimeout(() => {
             setIsSleeping(true); // Go to sleep
         }, 8000); // 8 seconds idle
     };

     const handleMouseMove = (e: MouseEvent) => {
        resetIdleTimer();
        if (!containerRef.current) return;

        const { innerWidth, innerHeight } = window;
        // Normalize coordinates (-1 to 1)
        const xNorm = (e.clientX - innerWidth / 2) / (innerWidth / 2);
        const yNorm = (e.clientY - innerHeight / 2) / (innerHeight / 2);

        // Head moves slightly
        setHeadRot({ x: xNorm * 15, y: yNorm * 10 });

        // Pupils move more to track
        setPupilPos({ x: xNorm * 12, y: yNorm * 8 });
     };

     window.addEventListener('mousemove', handleMouseMove);
     window.addEventListener('keydown', resetIdleTimer);

     // Start initial timer
     resetIdleTimer();

     return () => {
         window.removeEventListener('mousemove', handleMouseMove);
         window.removeEventListener('keydown', resetIdleTimer);
         if (idleTimer.current) clearTimeout(idleTimer.current);
     };
  }, [isSleeping]);

  const speak = (text: string, rate: number = 1.1, pitch: number = 1.4) => {
    if ('speechSynthesis' in window) {
        window.speechSynthesis.cancel();
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = 'vi-VN';
        utterance.rate = rate;
        utterance.pitch = pitch;
        const voices = window.speechSynthesis.getVoices();
        const viVoice = voices.find(v => v.lang.includes('vi'));
        if (viVoice) utterance.voice = viVoice;
        window.speechSynthesis.speak(utterance);
    }
  };

  const handleMascotClick = () => {
      setIsSleeping(false);
      setIsHappy(true);
      speak("Chào bạn! Hôm nay làm việc năng suất nhé!");
      setTimeout(() => setIsHappy(false), 2000);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!username.trim()) {
        // Error Animation
        setIsError(true);
        speak("Bạn ơi, quên nhập tên rồi kìa!", 1, 0.8);
        setTimeout(() => setIsError(false), 1000);
        return;
