interface Props {
  onLogin: () => void;
}

const Login: React.FC<Props> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [loading, setLoading] = useState(false);

  // --- MASCOT STATE ENGINE ---
  // Head tilt coordinates (for 3D effect)
  const [headRot, setHeadRot] = useState({ x: 0, y: 0 }); 
  // Pupil movement coordinates (eye tracking)
  const [pupilPos, setPupilPos] = useState({ x: 0, y: 0 }); 

  // Emotion States
  const [isSleeping, setIsSleeping] = useState(false);
  const [isError, setIsError] = useState(false);
  const [isHappy, setIsHappy] = useState(false);
  const [isFocused, setIsFocused] = useState(false); // Typing mode

  const idleTimer = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
     const lastUser = localStorage.getItem('ecogo_last_username');
     if (lastUser) setUsername(lastUser);

     // Pre-load voices for smoother experience
     if ('speechSynthesis' in window) {
         window.speechSynthesis.getVoices();
     }

     const resetIdleTimer = () => {
         if (idleTimer.current) clearTimeout(idleTimer.current);

         // Wake up logic
         if (isSleeping) {
             setIsSleeping(false); 
             speak("Á! Cậu chủ quay lại rồi.", 1.2, 1.3);
         }

         // Go to sleep after 8 seconds of inactivity
         idleTimer.current = setTimeout(() => {
             setIsSleeping(true); 
         }, 8000); 
     };

     const handleMouseMove = (e: MouseEvent) => {
        resetIdleTimer();
        if (!containerRef.current) return;

        const { innerWidth, innerHeight } = window;

        // Normalize mouse position (-1 to 1)
        const xNorm = (e.clientX - innerWidth / 2) / (innerWidth / 2);
        const yNorm = (e.clientY - innerHeight / 2) / (innerHeight / 2);

        // 1. Head Movement (Subtle tilt)
        // Limit rotation to +/- 15 degrees
        setHeadRot({ x: xNorm * 15, y: yNorm * 10 });

        // 2. Pupil Movement (Tracking)
        // Move pupils more than head to create depth
        setPupilPos({ x: xNorm * 14, y: yNorm * 10 });
     };

     window.addEventListener('mousemove', handleMouseMove);
     window.addEventListener('keydown', resetIdleTimer);
     window.addEventListener('click', resetIdleTimer);

     // Start initial timer
     resetIdleTimer();

     return () => {
         window.removeEventListener('mousemove', handleMouseMove);
         window.removeEventListener('keydown', resetIdleTimer);
         window.removeEventListener('click', resetIdleTimer);
         if (idleTimer.current) clearTimeout(idleTimer.current);
     };
  }, [isSleeping]);

