import React, { useState, useEffect, useRef } from 'react';
import { storageService } from '../services/storageService';

// Ensure variable is recognized
declare const __APP_VERSION__: string;

interface Props {
  onLogin: () => void;
}

const Login: React.FC<Props> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [loading, setLoading] = useState(false);

  // --- MASCOT STATE ---
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 }); // Normalized -1 to 1
  const [eyeOffset, setEyeOffset] = useState({ x: 0, y: 0 }); // Pixel offset for pupils
  const [isBlinking, setIsBlinking] = useState(false);
  const [mood, setMood] = useState<'IDLE' | 'HAPPY' | 'SAD' | 'FOCUSED' | 'LOADING' | 'SLEEP'>('IDLE');

  const containerRef = useRef<HTMLDivElement>(null);
  const mascotRef = useRef<HTMLDivElement>(null);
  const idleTimeout = useRef<any>(null);

  // 1. EYE TRACKING LOGIC (FIXED BOUNDARIES)
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!mascotRef.current) return;

      const rect = mascotRef.current.getBoundingClientRect();
      const faceCenterX = rect.left + rect.width / 2;
      const faceCenterY = rect.top + rect.height / 2;

      // Calculate raw distance
      const dx = e.clientX - faceCenterX;
      const dy = e.clientY - faceCenterY;

      // Normalize for Head Rotation (-1 to 1)
      // Dampen the values so head doesn't rotate too wildly
      const nX = Math.max(-1, Math.min(1, dx / (window.innerWidth / 1.5)));
      const nY = Math.max(-1, Math.min(1, dy / (window.innerHeight / 1.5)));
      setMousePos({ x: nX, y: nY });

      // Calculate Pupil Movement (Pixels)
      // Limit (Clamp) movement so pupils stay inside the eyes
      const maxEyeMoveX = 12; 
      const maxEyeMoveY = 8;
      // Calculate angle and distance to clamp properly in a circle/ellipse
      const angle = Math.atan2(dy, dx);
      const dist = Math.min(Math.sqrt(dx*dx + dy*dy) / 20, 1); // Distance factor

      setEyeOffset({
          x: Math.cos(angle) * dist * maxEyeMoveX,
          y: Math.sin(angle) * dist * maxEyeMoveY
      });

      resetIdle();
    };

    const resetIdle = () => {
        if (idleTimeout.current) clearTimeout(idleTimeout.current);
        if (mood === 'SLEEP') {
            setMood('IDLE');
            speak("Chào bạn!", 1.5);
        }
        if (mood !== 'FOCUSED' && mood !== 'LOADING') {
             idleTimeout.current = setTimeout(() => setMood('SLEEP'), 8000);
        }
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('keydown', resetIdle);
    window.addEventListener('click', resetIdle);

    // Auto Blink Loop
    const blinkLoop = () => {
        if (mood !== 'SLEEP') {
            setIsBlinking(true);
            setTimeout(() => setIsBlinking(false), 200);
        }
        setTimeout(blinkLoop, Math.random() * 3000 + 3000);
    };
    const blinkTimer = setTimeout(blinkLoop, 3000);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('keydown', resetIdle);
      window.removeEventListener('click', resetIdle);
      clearTimeout(blinkTimer);
      if (idleTimeout.current) clearTimeout(idleTimeout.current);
    };
  }, [mood]);

  // Load last user
  useEffect(() => {
      const last = localStorage.getItem('ecogo_last_username');
      if (last) setUsername(last);
  }, []);

  const speak = (text: string, pitch = 1.3) => {
      if ('speechSynthesis' in window) {
          window.speechSynthesis.cancel();
          const u = new SpeechSynthesisUtterance(text);
          u.lang = 'vi-VN';
          u.rate = 1.1; 
          u.pitch = pitch;
          const voices = window.speechSynthesis.getVoices();
          const vnVoice = voices.find(v => v.lang.includes('vi'));
          if (vnVoice) u.voice = vnVoice;
          window.speechSynthesis.speak(u);
      }
  };

  const handleInteract = () => {
      if (mood === 'LOADING') return;
      setMood('HAPPY');
      speak("Sẵn sàng làm việc!");
      setTimeout(() => setMood('IDLE'), 2000);
  };

  const handleSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (!username.trim()) {
          setMood('SAD');
          speak("Bạn ơi, nhập tên đi mà!", 0.8);
          setTimeout(() => setMood('IDLE'), 2000);
          return;
      }
      setLoading(true);
      setMood('LOADING');
      speak(`Đang vào hệ thống. Chào ${username}!`);
      setTimeout(() => {
          storageService.login(username);
          localStorage.setItem('ecogo_last_username', username);
          onLogin();
      }, 1500);
  };

  return (
    <div ref={containerRef} className="min-h-screen bg-gradient-to-br from-gray-50 via-slate-50 to-emerald-50 flex flex-col items-center justify-center relative overflow-hidden font-sans select-none perspective-1000">

      {/* Background Shapes */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
          <div className="absolute top-[-10%] left-[-10%] w-[60vh] h-[60vh] bg-emerald-300/10 rounded-full blur-[100px] animate-pulse"></div>
          <div className="absolute bottom-[-10%] right-[-10%] w-[60vh] h-[60vh] bg-blue-300/10 rounded-full blur-[100px] animate-pulse animation-delay-2000"></div>
      </div>

