                        {/* RIGHT EYE */}
                        <div className={`relative bg-slate-800 rounded-full overflow-hidden transition-all duration-300 ${mood === 'HAPPY' ? 'h-6 w-10 rounded-t-full rounded-b-lg scale-y-75' : (mood === 'SLEEP' ? 'h-1 w-10 bg-slate-600' : 'w-10 h-10')}`}>
                            {mood !== 'SLEEP' && (
                                <div className={`w-full h-full rounded-full opacity-20 ${mood === 'SAD' ? 'bg-red-500' : 'bg-emerald-400 animate-pulse-slow'}`}></div>
                            )}
                            {mood !== 'SLEEP' && !isBlinking && (
                                <div 
                                    className={`absolute w-6 h-6 rounded-full shadow-[0_0_15px_rgba(16,185,129,0.8)] transition-transform duration-75 ${mood === 'SAD' ? 'bg-red-500 shadow-red-500' : (mood === 'LOADING' ? 'bg-blue-400 animate-spin' : 'bg-emerald-400')}`}
                                    style={{ 
                                        left: '50%', top: '50%',
                                        marginLeft: '-12px', marginTop: '-12px',
                                        transform: `translate(${mood === 'FOCUSED' ? 0 : eyeOffset.x}px, ${mood === 'FOCUSED' ? 6 : eyeOffset.y}px) scale(${mood === 'HAPPY' ? 0.8 : 1})`
                                    }}
                                >
                                    <div className="absolute top-1 right-1 w-1.5 h-1.5 bg-white rounded-full opacity-80"></div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* === MOUTH === */}
                    <div className="h-8 flex items-center justify-center w-full z-20">
                        {/* Dynamic Mouth Shape using Border Radius */}
                        <div className={`transition-all duration-300 border-slate-400
