                              mood === 'SAD' ? 'w-6 h-3 border-t-2 rounded-t-full bg-transparent mt-2' : 
                              mood === 'SLEEP' ? 'w-2 h-2 rounded-full bg-slate-600 animate-pulse' :
                              mood === 'LOADING' ? 'w-4 h-4 rounded-full border-2 border-slate-500' :
                              username.length > 0 ? 'w-4 h-1.5 bg-emerald-500/50 rounded-full' :
                              'w-3 h-1 bg-slate-600 rounded-full'
                            }`}
