                        </button>
                    </div>
                    {/* Decor Icons */}
                    <i className="fas fa-star text-yellow-400 text-xl absolute top-6 left-6 animate-spin-slow"></i>
                    <i className="fas fa-star text-yellow-400 text-2xl absolute bottom-12 right-6 animate-pulse"></i>
