  [OrderStatus.IN_TRANSIT]: { bg: 'bg-purple-100', color: 'text-purple-800' },
  [OrderStatus.DELIVERED]: { bg: 'bg-green-100', color: 'text-green-800' },
  [OrderStatus.CANCELLED]: { bg: 'bg-red-100', color: 'text-red-800' },
