      window.dispatchEvent(new Event('storage_' + ORDER_KEY));
      if (isOnline()) {
          const batch = writeBatch(db);
          ids.forEach(id => batch.update(doc(db, "orders", id), { batchId: targetBatch, updatedAt: Date.now() }));
          await batch.commit();
      }
