      if (!editingOrder) return;
      const newItems = [...editingOrder.items];
      const item = { ...newItems[idx], [field]: val };

      // AUTO-PRICE LOGIC: If quantity changes, recalculate price based on tiers
      if (field === 'quantity' && item.productId) {
          const product = products.find(p => p.id === item.productId);
          if (product) {
              const qty = parseFloat(val) || 0;
              const { price } = calculateProductPrice(product, qty);
              item.price = price;
          }
