          {visibleOrders.length === 0 && (
              <div className="col-span-full py-20 flex flex-col items-center justify-center text-gray-300 opacity-60">
                  <i className="fas fa-box-open text-6xl mb-4"></i>
                  <span className="text-xs font-black uppercase tracking-widest">Không tìm thấy đơn hàng</span>
              </div>
          )}
      </div>

      {/* MODALS */}
      {editingOrder && (
          <div className="fixed inset-0 z-[100] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-2 sm:p-4 animate-fade-in" onClick={() => { setEditingOrder(null); setActiveEditProductRow(null); }}>
              <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-lg flex flex-col max-h-[90vh] overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-5 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                      <div>
                          <h3 className="font-black text-gray-800 uppercase tracking-tighter text-lg">Chỉnh sửa đơn hàng</h3>
                          <p className="text-[10px] text-gray-400 font-bold uppercase">{editingOrder.id} • {editingOrder.customerName}</p>
                      </div>
                      <button onClick={() => setEditingOrder(null)} className="w-8 h-8 rounded-full bg-white text-gray-400 hover:text-gray-600 flex items-center justify-center border border-gray-100"><i className="fas fa-times"></i></button>
                  </div>
                  <div className="flex-grow overflow-y-auto p-5 space-y-4">
                      {/* Customer Info Edit */}
                      <div className="grid grid-cols-2 gap-3">
                          <input value={editingOrder.customerName} onChange={e => setEditingOrder({...editingOrder, customerName: e.target.value})} className="col-span-1 p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs font-bold focus:border-black outline-none" placeholder="Tên khách" />
                          <input value={editingOrder.customerPhone} onChange={e => setEditingOrder({...editingOrder, customerPhone: e.target.value})} className="col-span-1 p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs font-bold focus:border-black outline-none" placeholder="Số điện thoại" />
                          <div className="col-span-2 relative">
                              <input value={editingOrder.address} onChange={e => setEditingOrder({...editingOrder, address: e.target.value})} className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs font-bold focus:border-black outline-none pr-10" placeholder="Địa chỉ" />
                              <button onClick={handleGetCurrentLocation} className={`absolute right-2 top-2 w-8 h-8 rounded-lg flex items-center justify-center text-gray-400 hover:bg-white hover:shadow-sm transition-all ${isGettingLocation ? 'animate-spin text-blue-500' : ''}`}><i className="fas fa-map-marker-alt"></i></button>
                          </div>
                      </div>

                      {/* Items Edit */}
                      <div className="space-y-2">
                          <div className="flex justify-between items-center">
                              <label className="text-[10px] font-black text-gray-400 uppercase">Danh sách hàng hóa</label>
                              <button onClick={addItemToEdit} className="text-[10px] font-bold text-eco-600 bg-eco-50 px-2 py-1 rounded-lg hover:bg-eco-100">+ Thêm món</button>
                          </div>
                          {editingOrder.items.map((item, idx) => {
                              // Calculate pricing info for badge
                              const product = products.find(p => p.id === item.productId);
                              let pricingInfo = null;
                              if (product && product.priceTiers && product.priceTiers.length > 0) {
                                  const { isWholesale } = calculateProductPrice(product, Number(item.quantity) || 0);
                                  pricingInfo = { isWholesale };
                              }

                              return (
                              <div key={idx} className="relative group bg-white border border-gray-200 rounded-xl p-2 flex gap-2 items-start product-dropdown-container shadow-sm">
                                  <div className="flex-grow relative">
                                      <input 
                                          value={item.name} 
                                          onChange={(e) => updateEditItem(idx, 'name', e.target.value)} 
                                          onFocus={() => setActiveEditProductRow(idx)}
                                          className="w-full p-1.5 bg-gray-50 rounded-lg text-xs font-bold outline-none border border-transparent focus:border-blue-200 uppercase" 
                                          placeholder="Tên sản phẩm..." 
                                      />
                                      {activeEditProductRow === idx && (
                                          <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-100 rounded-xl shadow-2xl z-[60] max-h-40 overflow-y-auto no-scrollbar">
                                              {products.filter(p => normalizeString(p.name).includes(normalizeString(item.name))).map(p => (
                                                  <div key={p.id} onClick={() => selectProductForEditItem(idx, p)} className="px-3 py-2 hover:bg-blue-50 cursor-pointer border-b border-gray-50 flex justify-between items-center">
                                                      <span className="text-[10px] font-bold text-gray-700 uppercase">{p.name}</span>
                                                      <span className="text-[10px] font-black text-blue-600">{new Intl.NumberFormat('vi-VN', { notation: "compact" }).format(p.defaultPrice)}</span>
                                                  </div>
                                              ))}
                                              <div onClick={() => { setEditingProduct(null); setEditProductMode('SET'); setShowProductModal(true); }} className="p-2 text-center text-[10px] font-bold text-eco-600 cursor-pointer bg-gray-50 hover:bg-gray-100">+ Tạo mới</div>
                                          </div>
                                      )}
                                  </div>
                                  <input 
                                      type="number" 
                                      step="any"
                                      value={item.quantity} 
                                      onChange={(e) => updateEditItem(idx, 'quantity', e.target.value)} 
                                      className="w-12 p-1.5 bg-gray-50 rounded-lg text-xs font-bold outline-none text-center border border-transparent focus:border-blue-200" 
                                      placeholder="SL" 
                                  />
                                  <div className="relative">
                                      <input 
                                          type="number" 
                                          value={item.price} 
                                          onChange={(e) => updateEditItem(idx, 'price', Number(e.target.value))} 
                                          className="w-20 p-1.5 bg-gray-50 rounded-lg text-xs font-bold outline-none text-right border border-transparent focus:border-blue-200" 
                                          placeholder="Giá" 
                                      />
                                      {/* PRICING BADGE */}
                                      {pricingInfo && (
                                          <div className={`absolute -top-2 right-0 text-[8px] font-bold px-1.5 py-0.5 rounded shadow-sm border border-white z-10 ${pricingInfo.isWholesale ? 'bg-purple-100 text-purple-700' : 'bg-gray-200 text-gray-500'}`}>
                                              {pricingInfo.isWholesale ? 'GIÁ SỈ' : 'GIÁ LẺ'}
                                          </div>
                                      )}
                                  </div>
                                  <button onClick={() => removeEditItem(idx)} className="w-7 h-7 flex items-center justify-center text-gray-300 hover:text-red-500"><i className="fas fa-times"></i></button>
                              </div>
