                          <input value={editingOrder.notes} onChange={e => setEditingOrder({...editingOrder, notes: e.target.value})} className="col-span-2 p-3 bg-yellow-50 border border-yellow-100 rounded-xl text-xs font-medium text-yellow-800 outline-none" placeholder="Ghi chú đơn hàng..." />
