                  </div>

                  <div className="flex gap-3">
                      <button onClick={() => setQrState({ isOpen: false, url: '', order: null })} className="flex-1 py-3 bg-gray-100 text-gray-600 rounded-xl font-bold text-xs uppercase hover:bg-gray-200 transition-all">Đóng</button>
                      <button onClick={handleShareQR} className="flex-1 py-3 bg-black text-white rounded-xl font-bold text-xs uppercase shadow-lg hover:bg-gray-800 transition-all flex items-center justify-center gap-2"><i className="fas fa-share-alt"></i> Chia sẻ</button>
                  </div>
              </div>
          </div>
      )}

      {/* DETAIL MODAL (COMPACT MODE) */}
      {detailOrder && (
          <div className="fixed inset-0 z-[110] bg-gray-900/60 backdrop-blur-sm flex items-end sm:items-center justify-center animate-fade-in" onClick={() => setDetailOrder(null)}>
              <div className="bg-white w-full sm:max-w-md sm:rounded-[2rem] rounded-t-[2rem] shadow-2xl max-h-[85vh] overflow-y-auto animate-slide-up" onClick={e => e.stopPropagation()}>
                  <div className="p-6">
                      <div className="flex justify-between items-start mb-4">
                          <div>
                              <h3 className="text-xl font-black text-gray-900 uppercase leading-tight">{detailOrder.customerName}</h3>
                              <div className="flex items-center gap-2 mt-1">
                                  <span className="bg-gray-100 px-2 py-0.5 rounded text-[10px] font-mono font-bold text-gray-600">{detailOrder.customerPhone}</span>
                                  <span className="bg-blue-50 px-2 py-0.5 rounded text-[10px] font-bold text-blue-600 uppercase">{detailOrder.batchId}</span>
                              </div>
                          </div>
                          <button onClick={() => setDetailOrder(null)} className="w-8 h-8 rounded-full bg-gray-50 flex items-center justify-center text-gray-400"><i className="fas fa-times"></i></button>
                      </div>

                      <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100 mb-4">
                          <p className="text-xs font-bold text-gray-700 leading-relaxed"><i className="fas fa-map-marker-alt text-red-500 mr-2"></i>{detailOrder.address}</p>
                          {detailOrder.notes && <p className="text-xs font-medium text-orange-600 mt-2 pt-2 border-t border-gray-200"><i className="fas fa-sticky-note mr-2"></i>{detailOrder.notes}</p>}
                      </div>

                      <div className="space-y-3 mb-6">
                          {detailOrder.items.map((item, idx) => (
                              <div key={idx} className="flex justify-between items-center py-2 border-b border-dashed border-gray-100">
                                  <div className="flex items-center gap-3">
                                      <div className="w-6 h-6 bg-gray-100 rounded flex items-center justify-center text-[10px] font-black text-gray-500">{item.quantity}</div>
                                      <span className="text-sm font-bold text-gray-800">{item.name}</span>
                                  </div>
                                  <span className="text-sm font-bold text-gray-900">{new Intl.NumberFormat('vi-VN').format(item.price * item.quantity)}</span>
                              </div>
                          ))}
                          <div className="flex justify-between items-center pt-2">
                              <span className="text-xs font-black text-gray-400 uppercase tracking-widest">Tổng cộng</span>
                              <span className="text-2xl font-black text-eco-600">{new Intl.NumberFormat('vi-VN').format(detailOrder.totalPrice)}đ</span>
                          </div>
                      </div>

                      <div className="grid grid-cols-2 gap-3">
                          <button onClick={() => handleEdit(detailOrder)} className="py-3 bg-gray-100 text-gray-700 rounded-xl font-bold text-xs uppercase hover:bg-gray-200">Chỉnh sửa</button>
                          <button onClick={() => handleSplitBatch(detailOrder)} className="py-3 bg-orange-100 text-orange-700 rounded-xl font-bold text-xs uppercase hover:bg-orange-200">Hoãn giao</button>
                          <button onClick={() => handleShowQR(detailOrder)} className="py-3 bg-blue-100 text-blue-700 rounded-xl font-bold text-xs uppercase hover:bg-blue-200 col-span-2">Lấy mã QR</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* OTHER MODALS */}
      <ConfirmModal isOpen={showDeleteConfirm} title="Xóa đơn hàng?" message="Hành động này không thể hoàn tác. Tồn kho sẽ được cộng lại." onConfirm={confirmDelete} onCancel={() => setShowDeleteConfirm(false)} confirmLabel="Xóa vĩnh viễn" isDanger={true} />
      <ConfirmModal isOpen={showBulkDeleteConfirm} title={`Xóa ${selectedOrderIds.size} đơn hàng?`} message="Các đơn hàng đã chọn sẽ bị xóa vĩnh viễn." onConfirm={confirmBulkDelete} onCancel={() => setShowBulkDeleteConfirm(false)} confirmLabel="Xóa hết" isDanger={true} />
      <ConfirmModal isOpen={showBulkStatusModal} title="Cập nhật trạng thái?" message={`Thay đổi trạng thái cho ${selectedOrderIds.size} đơn hàng đã chọn.`} onConfirm={() => {}} onCancel={() => setShowBulkStatusModal(false)} confirmLabel="Cập nhật" />
      {/* (Bulk Status Modal content needs to be injected into ConfirmModal or separate, simplifying here) */}
      {showBulkStatusModal && (
          <div className="fixed inset-0 z-[120] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-2xl p-5 w-full max-w-xs shadow-2xl">
                  <h3 className="font-black text-gray-800 uppercase mb-4 text-center">Chọn trạng thái mới</h3>
                  <div className="space-y-2">
                      {Object.values(OrderStatus).map(s => (
                          <button key={s} onClick={() => handleBulkStatusChange(s)} className="w-full py-3 bg-gray-50 hover:bg-gray-100 rounded-xl font-bold text-xs text-gray-700 uppercase transition-colors">{statusLabels[s]}</button>
                      ))}
                  </div>
                  <button onClick={() => setShowBulkStatusModal(false)} className="w-full mt-4 py-2 text-gray-400 font-bold text-xs hover:text-gray-600">Hủy bỏ</button>
              </div>
          </div>
      )}

      {/* Move Batch Modal */}
      {moveBatchData.isOpen && (
          <div className="fixed inset-0 z-[120] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-2xl p-5 w-full max-w-xs shadow-2xl">
                  <h3 className="font-black text-gray-800 uppercase mb-4 text-center">Chuyển sang lô nào?</h3>
                  <div className="max-h-60 overflow-y-auto space-y-2 no-scrollbar">
                      {uniqueBatches.map(b => (
                          <button key={b} onClick={() => setMoveBatchData({ ...moveBatchData, targetBatch: b })} className={`w-full py-3 rounded-xl font-bold text-xs uppercase transition-colors ${moveBatchData.targetBatch === b ? 'bg-purple-600 text-white' : 'bg-gray-50 text-gray-700 hover:bg-gray-100'}`}>{b}</button>
                      ))}
                      <div className="pt-2 border-t border-gray-100">
                          <input placeholder="Hoặc nhập tên lô mới..." className="w-full p-2 bg-white border-2 border-gray-200 rounded-lg text-xs font-bold outline-none focus:border-purple-500 uppercase" onChange={(e) => setMoveBatchData({...moveBatchData, targetBatch: e.target.value})} />
                      </div>
                  </div>
                  <div className="flex gap-2 mt-4">
                      <button onClick={() => setMoveBatchData({ isOpen: false, targetBatch: '' })} className="flex-1 py-2 bg-gray-100 rounded-lg font-bold text-xs text-gray-500">Hủy</button>
                      <button onClick={handleMoveBatch} disabled={!moveBatchData.targetBatch} className="flex-1 py-2 bg-purple-600 text-white rounded-lg font-bold text-xs shadow-md disabled:bg-gray-300">Chuyển</button>
                  </div>
              </div>
          </div>
      )}

      {/* PRINT TYPE MODAL */}
      {showPrintTypeModal && (
          <div className="fixed inset-0 z-[120] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-[2rem] p-6 w-full max-w-sm shadow-2xl text-center">
                  <h3 className="font-black text-xl text-gray-900 uppercase italic tracking-tighter mb-2">Chọn mẫu in</h3>
                  <p className="text-xs font-bold text-gray-400 mb-6">Bạn muốn in {ordersToPrint.length > 0 ? ordersToPrint.length : selectedOrderIds.size} đơn hàng theo kiểu nào?</p>

                  <div className="grid grid-cols-2 gap-4">
                      <button onClick={handlePrintBatch} disabled={isPrinting} className="bg-gray-50 border-2 border-gray-200 hover:border-gray-900 rounded-2xl p-4 flex flex-col items-center gap-3 transition-all group">
                          <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-2xl shadow-sm group-hover:scale-110 transition-transform">🏷️</div>
                          <span className="font-black text-xs uppercase text-gray-700">Tem dán<br/>(8 tem/A4)</span>
                      </button>
                      <button onClick={handlePrintCompact} disabled={isPrinting} className="bg-gray-50 border-2 border-gray-200 hover:border-gray-900 rounded-2xl p-4 flex flex-col items-center gap-3 transition-all group">
                          <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-2xl shadow-sm group-hover:scale-110 transition-transform">📋</div>
                          <span className="font-black text-xs uppercase text-gray-700">Danh sách<br/>(Manifest)</span>
                      </button>
                  </div>

                  {isPrinting && (
                      <div className="mt-6">
                          <div className="w-full bg-gray-100 rounded-full h-2 overflow-hidden">
                              <div className="bg-eco-500 h-full transition-all duration-300" style={{ width: `${printProgress}%` }}></div>
                          </div>
                          <p className="text-[10px] font-bold text-eco-600 mt-2 uppercase tracking-widest">Đang xử lý PDF... {printProgress}%</p>
                      </div>
                  )}

                  {!isPrinting && <button onClick={() => setShowPrintTypeModal(false)} className="mt-6 text-xs font-bold text-gray-400 hover:text-gray-600">Đóng lại</button>}
              </div>
          </div>
      )}

      {/* Global Product Modals */}
      <ProductEditModal 
        isOpen={showProductModal} 
        onClose={() => { setEditingProduct(null); setShowProductModal(false); }} 
        product={editingProduct} 
        onSave={handleSaveProduct} 
        initialMode={editProductMode} 
        allProducts={products}
        onSwitchToProduct={(p) => { setEditingProduct(p); setEditProductMode('SET'); setShowProductModal(true); }}
      />
      <ConfirmModal 
          isOpen={showSyncConfirm} 
          title="Đồng bộ đơn hàng?" 
          message="Bạn có muốn cập nhật thông tin mới (Giá/Tên) cho các đơn hàng CHỜ XỬ LÝ không?" 
          onConfirm={handleConfirmSync} 
          onCancel={() => { setShowSyncConfirm(false); setPendingProductUpdate(null); }}
          confirmLabel="Đồng bộ ngay"
          cancelLabel="Chỉ sửa kho"
      />

      <RoutePlannerModal isOpen={showRoutePlanner} onClose={() => setShowRoutePlanner(false)} orders={filteredOrders} onApplySort={handleApplySort} />
      <ShipperSummaryModal isOpen={showShipperSummary} onClose={() => setShowShipperSummary(false)} orders={filteredOrders} batchName={filterBatch.join('+') || 'Tất cả'} />
    </div>
  );
};

export default TrackingDashboard;

import React, { useState, useEffect, useRef } from 'react';
import toast from 'react-hot-toast';
import { v4 as uuidv4 } from 'uuid';
import { Order, OrderItem, Product, PaymentMethod } from '../types';
import { storageService, calculateProductPrice, normalizeString } from '../services/storageService';

interface Props {
    isOpen: boolean;
    onClose: () => void;
    order: Order;
    products: Product[];
    onSave: () => void; // Trigger parent refresh
}

const OrderEditModal: React.FC<Props> = ({ isOpen, onClose, order, products, onSave }) => {
    const [localOrder, setLocalOrder] = useState<Order | null>(null);
    const [activeProductRow, setActiveProductRow] = useState<number | null>(null);
    const [isGettingLocation, setIsGettingLocation] = useState(false);

    useEffect(() => {
        if (isOpen && order) {
            setLocalOrder(JSON.parse(JSON.stringify(order)));
        } else {
            setLocalOrder(null);
        }
    }, [isOpen, order]);

    // Handle Click Outside for Product Dropdown
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (activeProductRow !== null && !(event.target as Element).closest('.product-dropdown-container')) {
                setActiveProductRow(null);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [activeProductRow]);

    const handleUpdate = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!localOrder) return;

        const total = localOrder.items.reduce((s, i) => s + (i.price * i.quantity), 0);
        const updated = { ...localOrder, totalPrice: total };

        await storageService.updateOrderDetails(updated);
        toast.success('Đã cập nhật đơn hàng');
        onSave();
        onClose();
    };

    const updateItem = (idx: number, field: keyof OrderItem, val: any) => {
        if (!localOrder) return;
        const newItems = [...localOrder.items];
        const item = { ...newItems[idx], [field]: val };

        // SMART PRICING LOGIC
        if (field === 'quantity' && item.productId) {
            const product = products.find(p => p.id === item.productId);
            if (product) {
                const qty = parseFloat(val) || 0;
                // Calculate price based on new quantity
                const { price } = calculateProductPrice(product, qty);
                item.price = price;
            }
        }

        newItems[idx] = item;

        // Auto-calc total for preview
        const newTotal = newItems.reduce((s, i) => s + (i.price * i.quantity), 0);
        setLocalOrder({ ...localOrder, items: newItems, totalPrice: newTotal });
    };

    const selectProductForItem = (idx: number, product: Product) => {
        if (!localOrder) return;
        const newItems = [...localOrder.items];

        // Use current quantity in input or default to 1
        const currentQty = Number(newItems[idx].quantity) || 1;

        // Calculate Price
        const { price } = calculateProductPrice(product, currentQty);

        newItems[idx] = {
            ...newItems[idx],
            productId: product.id,
            name: product.name,
            price: price,
            importPrice: product.importPrice
        };

        const newTotal = newItems.reduce((s, i) => s + (i.price * i.quantity), 0);
        setLocalOrder({ ...localOrder, items: newItems, totalPrice: newTotal });
        setActiveProductRow(null);
    };

    const addItem = () => {
        if (!localOrder) return;
        setLocalOrder({ 
            ...localOrder, 
            items: [...localOrder.items, { id: uuidv4(), name: '', quantity: 1, price: 0 }] 
        });
    };

    const removeItem = (idx: number) => {
        if (!localOrder) return;
        const newItems = [...localOrder.items];
        newItems.splice(idx, 1);
        const newTotal = newItems.reduce((s, i) => s + (i.price * i.quantity), 0);
        setLocalOrder({ ...localOrder, items: newItems, totalPrice: newTotal });
    };

    const handleGetCurrentLocation = () => {
        if (!navigator.geolocation) {
            toast.error("Trình duyệt không hỗ trợ");
            return;
        }
        setIsGettingLocation(true);
        navigator.geolocation.getCurrentPosition(async (position) => {
            const { latitude, longitude } = position.coords;
            try {
                const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&zoom=18&addressdetails=1`);
                const data = await response.json();
                if (data && data.display_name && localOrder) {
                    setLocalOrder({ ...localOrder, address: data.display_name });
                    toast.success("Đã lấy địa chỉ hiện tại!");
                }
            } catch (e) { toast.error("Lỗi lấy địa chỉ"); } finally { setIsGettingLocation(false); }
        }, () => { toast.error("Không thể lấy vị trí"); setIsGettingLocation(false); }, { enableHighAccuracy: true });
    };

    if (!isOpen || !localOrder) return null;

    return (
        <div className="fixed inset-0 z-[100] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-2 sm:p-4 animate-fade-in" onClick={onClose}>
            <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-lg flex flex-col max-h-[90vh] overflow-hidden" onClick={e => e.stopPropagation()}>

                {/* Header */}
                <div className="p-5 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                    <div>
                        <h3 className="font-black text-gray-800 uppercase tracking-tighter text-lg flex items-center gap-2">
                            <i className="fas fa-edit text-blue-600"></i> Chỉnh sửa đơn hàng
                        </h3>
                        <p className="text-[10px] text-gray-400 font-bold uppercase">{localOrder.id} • {localOrder.customerName}</p>
                    </div>
                    <button onClick={onClose} className="w-8 h-8 rounded-full bg-white text-gray-400 hover:text-gray-600 flex items-center justify-center border border-gray-100"><i className="fas fa-times"></i></button>
                </div>

                {/* Body */}
                <form onSubmit={handleUpdate} className="flex-grow overflow-y-auto p-5 space-y-4">

                    {/* Customer Info */}
                    <div className="grid grid-cols-2 gap-3">
                        <div className="group">
                            <label className="text-[10px] font-black text-gray-400 uppercase ml-1 block mb-1">Tên khách</label>
                            <input value={localOrder.customerName} onChange={e => setLocalOrder({...localOrder, customerName: e.target.value})} className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs font-bold focus:border-black outline-none transition-colors" placeholder="Tên khách" />
                        </div>
                        <div className="group">
                            <label className="text-[10px] font-black text-gray-400 uppercase ml-1 block mb-1">Số điện thoại</label>
                            <input value={localOrder.customerPhone} onChange={e => setLocalOrder({...localOrder, customerPhone: e.target.value})} className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs font-bold focus:border-black outline-none transition-colors" placeholder="Số điện thoại" />
                        </div>
                        <div className="col-span-2 relative group">
                            <label className="text-[10px] font-black text-gray-400 uppercase ml-1 block mb-1">Địa chỉ</label>
                            <input value={localOrder.address} onChange={e => setLocalOrder({...localOrder, address: e.target.value})} className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs font-bold focus:border-black outline-none pr-10 transition-colors" placeholder="Địa chỉ" />
                            <button type="button" onClick={handleGetCurrentLocation} className={`absolute right-2 top-7 w-8 h-8 rounded-lg flex items-center justify-center text-gray-400 hover:bg-white hover:shadow-sm transition-all ${isGettingLocation ? 'animate-spin text-blue-500' : ''}`}><i className="fas fa-map-marker-alt"></i></button>
                        </div>
                    </div>

                    {/* Items List */}
                    <div className="space-y-2">
                        <div className="flex justify-between items-center">
                            <label className="text-[10px] font-black text-gray-400 uppercase">Danh sách hàng hóa</label>
                            <button type="button" onClick={addItem} className="text-[10px] font-bold text-eco-600 bg-eco-50 px-2 py-1 rounded-lg hover:bg-eco-100 border border-eco-100">+ Thêm món</button>
                        </div>
                        {localOrder.items.map((item, idx) => {
                            // Determine Pricing Badge
                            const product = products.find(p => p.id === item.productId);
                            let pricingBadge = null;

                            // Condition: Show badge only if product has multiple tiers
                            if (product && product.priceTiers && product.priceTiers.length > 0) {
                                const { isWholesale } = calculateProductPrice(product, Number(item.quantity) || 0);
                                pricingBadge = (
                                    <div className={`absolute -top-2 right-0 text-[8px] font-black px-1.5 py-0.5 rounded shadow-sm border border-white z-10 ${isWholesale ? 'bg-purple-100 text-purple-700' : 'bg-gray-200 text-gray-500'}`}>
                                        {isWholesale ? 'GIÁ SỈ' : 'GIÁ LẺ'}
                                    </div>
                                );
                            }

                            return (
                            <div key={idx} className="relative group bg-white border border-gray-200 rounded-xl p-2 flex gap-2 items-start product-dropdown-container shadow-sm hover:border-blue-300 transition-colors">
                                <div className="flex-grow relative">
                                    <input 
                                        value={item.name} 
                                        onChange={(e) => updateItem(idx, 'name', e.target.value)} 
                                        onFocus={() => setActiveProductRow(idx)}
                                        className="w-full p-1.5 bg-gray-50 rounded-lg text-xs font-bold outline-none border border-transparent focus:border-blue-200 uppercase focus:bg-white transition-colors" 
                                        placeholder="Tên sản phẩm..." 
                                    />
                                    {activeProductRow === idx && (
                                        <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-100 rounded-xl shadow-2xl z-[60] max-h-40 overflow-y-auto no-scrollbar animate-scale-in">
                                            {products.filter(p => normalizeString(p.name).includes(normalizeString(item.name))).map(p => (
                                                <div key={p.id} onMouseDown={() => selectProductForItem(idx, p)} className="px-3 py-2 hover:bg-blue-50 cursor-pointer border-b border-gray-50 flex justify-between items-center group/item">
                                                    <div className="flex flex-col">
                                                        <span className="text-[10px] font-bold text-gray-700 uppercase group-hover/item:text-blue-700">{p.name}</span>
                                                        <span className="text-[8px] text-gray-400">Tồn: {p.stockQuantity}</span>
                                                    </div>
                                                    <span className="text-[10px] font-black text-blue-600">{new Intl.NumberFormat('vi-VN', { notation: "compact" }).format(p.defaultPrice)}</span>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                                <input 
                                    type="number" 
                                    step="any"
                                    value={item.quantity} 
                                    onChange={(e) => updateItem(idx, 'quantity', e.target.value)} 
                                    className="w-12 p-1.5 bg-gray-50 rounded-lg text-xs font-bold outline-none text-center border border-transparent focus:border-blue-200 focus:bg-white transition-colors" 
                                    placeholder="SL" 
                                />
                                <div className="relative">
                                    <input 
                                        type="number" 
                                        value={item.price} 
                                        onChange={(e) => updateItem(idx, 'price', Number(e.target.value))} 
                                        className="w-20 p-1.5 bg-gray-50 rounded-lg text-xs font-bold outline-none text-right border border-transparent focus:border-blue-200 focus:bg-white transition-colors" 
                                        placeholder="Giá" 
                                    />
                                    {pricingBadge}
                                </div>
                                <button type="button" onClick={() => removeItem(idx)} className="w-7 h-7 flex items-center justify-center text-gray-300 hover:text-red-500 transition-colors"><i className="fas fa-times"></i></button>
                            </div>
                            );
                        })}
                    </div>

                    {/* Payment & Notes */}
                    <div className="space-y-3 pt-2 border-t border-gray-100">
                        <div>
                            <label className="text-[10px] font-black text-gray-400 uppercase ml-1 block mb-1">Hình thức thanh toán</label>
                            <div className="flex bg-gray-100 p-1 rounded-xl">
                                {[
                                    { id: PaymentMethod.CASH, label: 'Tiền mặt', icon: 'fa-money-bill-wave', color: 'text-green-700', activeBg: 'bg-white shadow-sm' },
                                    { id: PaymentMethod.TRANSFER, label: 'Chuyển khoản', icon: 'fa-university', color: 'text-blue-700', activeBg: 'bg-white shadow-sm' },
                                    { id: PaymentMethod.PAID, label: 'Đã trả trước', icon: 'fa-check-circle', color: 'text-purple-700', activeBg: 'bg-white shadow-sm' }
                                ].map((method) => (
                                    <button
                                        key={method.id}
                                        type="button"
                                        onClick={() => setLocalOrder({...localOrder, paymentMethod: method.id, paymentVerified: method.id === PaymentMethod.PAID })}
                                        className={`flex-1 py-2 rounded-lg text-[10px] font-bold transition-all flex items-center justify-center gap-1 ${localOrder.paymentMethod === method.id ? `${method.activeBg} ${method.color}` : 'text-gray-500 hover:text-gray-700'}`}
                                    >
                                        <i className={`fas ${method.icon}`}></i> {method.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="grid grid-cols-1 gap-3">
