                        <div className="text-[10px] font-black text-gray-400 uppercase">Tổng thanh toán</div>
                        <div className="text-xl font-black text-gray-900">{new Intl.NumberFormat('vi-VN').format(localOrder.items.reduce((s, i) => s + (i.price * i.quantity), 0))}đ</div>
                    </div>
                    <button onClick={handleUpdate} className="flex-1 py-3.5 bg-black text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl hover:bg-gray-800 transition-all active:scale-95">
                        Lưu thay đổi <i className="fas fa-check-circle ml-1"></i>
                    </button>
                </div>
            </div>
        </div>
    );
};

