          ([entry]) => { setIsHeaderVisible(entry.isIntersecting); setActiveDropdown(null); },
          { threshold: 0, rootMargin: "-70px 0px 0px 0px" }
      );
      if (observerTarget.current) observer.observe(observerTarget.current);
      return () => observer.disconnect();
  }, []);

  useEffect(() => {
    const unsubOrders = storageService.subscribeOrders(setOrders);
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);

    const handleWindowEvents = () => setActiveDropdown(null);
    window.addEventListener('resize', handleWindowEvents);
    window.addEventListener('scroll', handleWindowEvents, true);
    return () => { 
        if (unsubOrders) unsubOrders(); 
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers(); 
        window.removeEventListener('resize', handleWindowEvents); 
        window.removeEventListener('scroll', handleWindowEvents, true); 
    };
  }, []);

  useEffect(() => {
      if (qrState.isOpen && qrState.url) {
          storageService.getShopConfig().then(c => shopConfigRef.current = c);
          storageService.getBankConfig().then(c => bankConfigRef.current = c);
          const img = new Image();
          img.crossOrigin = "Anonymous";
          img.src = qrState.url;
          img.onload = () => {
              qrImgRef.current = img;
          };
      } else {
          qrImgRef.current = null;
      }
  }, [qrState.isOpen, qrState.url]);

  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (activeDropdown) {
              const dropdownEl = document.getElementById('floating-dropdown-portal');
              const statusBtn = statusDropdownBtnRef.current;
              const batchBtn = batchDropdownBtnRef.current;
              if (dropdownEl && !dropdownEl.contains(event.target as Node) && statusBtn && !statusBtn.contains(event.target as Node) && batchBtn && !batchBtn.contains(event.target as Node)) setActiveDropdown(null);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [activeDropdown]);

  const handleViewDetail = (order: Order) => {
      setDetailOrder(order);
  };

  const handleDeleteClick = useCallback((id: string) => { setDeleteId(id); setShowDeleteConfirm(true); }, []);
  const handleEdit = useCallback((order: Order) => { setEditingOrder(JSON.parse(JSON.stringify(order))); setDetailOrder(null); }, []);
  const handleSplitBatch = useCallback(async (order: Order) => { await storageService.splitOrderToNextBatch(order.id, order.batchId); toast.success('Đã chuyển đơn sang lô sau!'); if(detailOrder?.id === order.id) setDetailOrder(null); }, [detailOrder]);

  const handleShowQR = useCallback(async (order: Order) => { 
      const bankConfig = await storageService.getBankConfig(); 
      if (!bankConfig || !bankConfig.accountNo) { 
          toast.error("Vui lòng cài đặt thông tin Ngân hàng trước."); 
          return; 
      }
      let cleanName = normalizeString(order.customerName).toUpperCase();
      cleanName = cleanName.replace(/[^A-Z0-9 ]/g, '');
      if (cleanName.length > 25) {
          cleanName = cleanName.substring(0, 25).trim();
      }
      const desc = `DH ${order.id} ${cleanName}`; 
      const url = `https://img.vietqr.io/image/${bankConfig.bankId}-${bankConfig.accountNo}-${bankConfig.template || 'compact2'}.png?amount=${order.totalPrice}&addInfo=${encodeURIComponent(String(desc))}&accountName=${encodeURIComponent(String(bankConfig.accountName))}`; 
      setQrState({ isOpen: true, url, order }); 
  }, []);

  const handleShareQR = async () => {
        if (!qrState.url || !qrState.order) return;

        try {
            const H = 800; const W = 600; const cardMargin = 40;
            const canvas = document.createElement('canvas'); const ctx = canvas.getContext('2d'); if (!ctx) return;
            canvas.width = W; canvas.height = H;
            ctx.fillStyle = '#F8FAFC'; ctx.fillRect(0, 0, W, H);

            const cardY = 60; const cardH = H - 120;
            ctx.shadowColor = "rgba(0, 0, 0, 0.1)"; ctx.shadowBlur = 30; ctx.shadowOffsetY = 15; ctx.fillStyle = '#FFFFFF';
            if ((ctx as any).roundRect) { ctx.beginPath(); (ctx as any).roundRect(cardMargin, cardY, W - cardMargin*2, cardH, 40); ctx.fill(); } else { ctx.fillRect(cardMargin, cardY, W - cardMargin*2, cardH); }
            ctx.shadowColor = "transparent";

            let cursorY = cardY + 80;
            const shopName = (shopConfigRef.current?.shopName || 'ECOGO STORE').toUpperCase();
            ctx.fillStyle = '#166534'; ctx.font = 'bold 32px Arial, sans-serif'; ctx.textAlign = 'center'; ctx.fillText(shopName, W/2, cursorY); cursorY += 50;
            ctx.fillStyle = '#64748B'; ctx.font = 'bold 20px Arial, sans-serif'; ctx.fillText('THANH TOÁN ĐƠN HÀNG', W/2, cursorY); cursorY += 60;
            ctx.fillStyle = '#DC2626'; ctx.font = 'bold 60px Arial, sans-serif'; ctx.fillText(`${new Intl.NumberFormat('vi-VN').format(qrState.order.totalPrice)}đ`, W/2, cursorY); cursorY += 50;

            if (qrImgRef.current) {
                const qrSize = 350;
                ctx.drawImage(qrImgRef.current, (W - qrSize)/2, cursorY, qrSize, qrSize * (qrImgRef.current.height / qrImgRef.current.width));
                cursorY += qrSize + 40;
            }

            if (bankConfigRef.current) {
                ctx.fillStyle = '#64748B'; ctx.font = 'italic 16px Arial, sans-serif';
                ctx.fillText(`Ngân hàng: ${bankConfigRef.current.bankId} - ${bankConfigRef.current.accountNo}`, W/2, cursorY);
                ctx.fillText(`Chủ TK: ${bankConfigRef.current.accountName}`, W/2, cursorY + 25);
            }

            const dataUrl = canvas.toDataURL('image/png');
            const file = dataURLtoFile(dataUrl, `QR-${qrState.order.id}.png`);
            if (navigator.share) {
                await navigator.share({ files: [file], title: `Thanh toán ${qrState.order.id}`, text: `Mã QR thanh toán cho đơn hàng ${qrState.order.id}` } as any);
            } else {
                const a = document.createElement('a'); a.href = dataUrl; a.download = `QR-${qrState.order.id}.png`; a.click();
            }
        } catch (e) { toast.error("Không thể chia sẻ ảnh QR"); }
  };

  const handleDragStart = (e: React.DragEvent<HTMLDivElement>, index: number) => { dragItem.current = index; e.dataTransfer.effectAllowed = "move"; e.currentTarget.classList.add('opacity-50'); };
  const handleDragEnter = (e: React.DragEvent<HTMLDivElement>, index: number) => { dragOverItem.current = index; e.preventDefault(); };
  const handleDragEnd = (e: React.DragEvent<HTMLDivElement>) => { e.currentTarget.classList.remove('opacity-50'); if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) { const newOrders = [...orders]; const movedItem = newOrders.splice(dragItem.current, 1)[0]; newOrders.splice(dragOverItem.current, 0, movedItem); setOrders(newOrders); storageService.learnRoutePriority(newOrders); } dragItem.current = null; dragOverItem.current = null; };
  const handleVoiceSearch = () => { const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition; if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ"); return; } const recognition = new SpeechRecognition(); recognition.lang = 'vi-VN'; recognition.onstart = () => setIsListeningSearch(true); recognition.onend = () => setIsListeningSearch(false); recognition.onresult = (event: any) => { setSearchTerm(event.results[0][0].transcript); }; recognition.start(); };
  const confirmDelete = async () => { if (deleteId) { await storageService.deleteOrder(deleteId); toast.success('Đã xóa đơn hàng'); setShowDeleteConfirm(false); if(detailOrder?.id === deleteId) setDetailOrder(null); } };

  const handleSelectOrder = (id: string) => { setSelectedOrderIds(prev => { const next = new Set(prev); if (next.has(id)) next.delete(id); else next.add(id); if(next.size === 0) setIsSelectionMode(false); return next; }); };
  const handleLongPressOrder = (id: string) => { setIsSelectionMode(true); setSelectedOrderIds(new Set([id])); if (navigator.vibrate) navigator.vibrate(50); };
  const handleSelectAll = () => { if (selectedOrderIds.size === filteredOrders.length) setSelectedOrderIds(new Set()); else setSelectedOrderIds(new Set(filteredOrders.map(o => o.id))); };
  const exitSelectionMode = () => { setIsSelectionMode(false); setSelectedOrderIds(new Set()); };
  const handleBulkDelete = () => { setShowBulkDeleteConfirm(true); };
  const confirmBulkDelete = async () => { await storageService.deleteOrdersBatch(Array.from(selectedOrderIds) as string[]); toast.success(`Đã xóa ${selectedOrderIds.size} đơn`); exitSelectionMode(); setShowBulkDeleteConfirm(false); };
  const handleBulkStatusChange = (status: OrderStatus) => { const ids = Array.from(selectedOrderIds); ids.forEach(id => storageService.updateStatus(id, status)); toast.success(`Cập nhật ${ids.length} đơn: ${statusLabels[status]}`); exitSelectionMode(); setShowBulkStatusModal(false); };

  const handlePrintBatch = async () => { 
      const selected = ordersToPrint.length > 0 ? ordersToPrint : (isSelectionMode && selectedOrderIds.size > 0 ? filteredOrders.filter(o => selectedOrderIds.has(o.id)) : filteredOrders); 
      setIsPrinting(true); 
      try { 
          await pdfService.generateInvoiceBatch(selected, filterBatch.join('+') || 'ALL', (progress) => setPrintProgress(progress)); 
          toast.success("Đã tạo file in PDF"); 
      } catch (e) { 
          toast.error("Lỗi tạo PDF"); 
      } finally { 
          setIsPrinting(false); 
          setPrintProgress(0); 
          setShowPrintTypeModal(false); 
      } 
  };

  const handlePrintCompact = async () => { 
      const selected = ordersToPrint.length > 0 ? ordersToPrint : (isSelectionMode && selectedOrderIds.size > 0 ? filteredOrders.filter(o => selectedOrderIds.has(o.id)) : filteredOrders); 
      setIsPrinting(true); 
      try { 
          await pdfService.generateCompactList(selected, filterBatch.join('+') || 'Danh Sach', (progress) => setPrintProgress(progress)); 
          toast.success("Đã tạo danh sách PDF"); 
      } catch (e) { 
          toast.error("Lỗi tạo PDF"); 
      } finally { 
          setIsPrinting(false); 
          setPrintProgress(0); 
          setShowPrintTypeModal(false); 
      } 
  };

  const preparePrint = (orders: Order[]) => { setOrdersToPrint(orders); setShowPrintTypeModal(true); };

  const handleApplySort = (sorted: Order[]) => { setOrders(sorted); toast.success("Đã sắp xếp theo lộ trình"); };
  const handleMoveBatch = async () => { if (!moveBatchData.targetBatch) return; const ids = Array.from(selectedOrderIds); await storageService.moveOrdersBatch(ids, moveBatchData.targetBatch); toast.success(`Đã chuyển ${ids.length} đơn sang ${moveBatchData.targetBatch}`); exitSelectionMode(); setMoveBatchData({ isOpen: false, targetBatch: '' }); };

  const handlePinCurrentLocation = () => {
      if (!detailOrder) return;
      if (!navigator.geolocation) {
          toast.error("Trình duyệt không hỗ trợ");
          return;
      }
      setIsGettingLocation(true);
      navigator.geolocation.getCurrentPosition(async (position) => {
          const { latitude, longitude } = position.coords;
          try {
              const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&zoom=18&addressdetails=1`);
              const data = await response.json();
              if (data && data.display_name) {
                  const updatedOrder = { ...detailOrder, address: data.display_name };
                  await storageService.updateOrderDetails(updatedOrder);
                  setDetailOrder(updatedOrder);
                  toast.success("Đã ghim vị trí chính xác!", { icon: '📍' });
              } else {
                  toast.error("Không tìm thấy địa chỉ từ tọa độ này");
              }
          } catch (e) { toast.error("Lỗi lấy địa chỉ bản đồ"); } finally { setIsGettingLocation(false); }
      }, () => { toast.error("Không thể lấy vị trí"); setIsGettingLocation(false); }, { enableHighAccuracy: true });
  };

  const handleSaveProduct = async (data: Product, isImport: boolean = false, qty: number = 0) => {
        if (isImport && editingProduct) {
            await storageService.adjustStockAtomic(editingProduct.id, qty, { price: data.importPrice || 0, note: 'Nhập hàng' });
            if (data.name !== editingProduct.name || data.defaultPrice !== editingProduct.defaultPrice) { await storageService.saveProduct({ ...editingProduct, name: data.name, defaultPrice: data.defaultPrice, importPrice: data.importPrice }); }
            toast.success("Đã nhập hàng");
        } else {
            await storageService.saveProduct(data);
            if (editingProduct) { 
                setPendingProductUpdate(data); 
                setShowSyncConfirm(true); 
            } else { 
                toast.success('Đã tạo hàng mới'); 
            }
        }
  };

  const handleConfirmSync = async () => {
        if (pendingProductUpdate) {
            const count = await storageService.syncProductToPendingOrders(pendingProductUpdate);
            if (count > 0) {
                toast.success(`Đã đồng bộ cho ${count} đơn hàng chờ.`);
            } else {
                toast("Không có đơn chờ nào cần cập nhật.");
            }
        }
        setShowSyncConfirm(false);
        setPendingProductUpdate(null);
  };

  const uniqueBatches = useMemo(() => Array.from(new Set(orders.map(o => o.batchId || 'Chưa phân lô'))).sort().reverse(), [orders]);

  const filteredOrders = useMemo(() => {
      let res = orders;
      if (filterStatus.length > 0) res = res.filter(o => filterStatus.includes(o.status));
      if (filterBatch.length > 0) res = res.filter(o => filterBatch.includes(o.batchId || 'Chưa phân lô'));
      if (deferredSearchTerm) {
          const lower = normalizeString(deferredSearchTerm);
          res = res.filter(o => normalizeString(o.customerName).includes(lower) || o.customerPhone.includes(lower) || normalizeString(o.address).includes(lower));
      }
      if (sortBy === 'ROUTE') { /* Handled manually via DragNDrop or RoutePlanner */ } 
      else if (sortBy === 'STATUS') res.sort((a,b) => a.status.localeCompare(b.status));

      return res;
  }, [orders, filterStatus, filterBatch, deferredSearchTerm, sortBy]);

  const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
      const { scrollTop, scrollHeight, clientHeight } = e.currentTarget;
      if (scrollHeight - scrollTop - clientHeight < 300) {
          setVisibleCount(prev => Math.min(prev + 20, filteredOrders.length));
      }
  };

  const visibleOrders = filteredOrders.slice(0, visibleCount);

  return (
    <div className="max-w-6xl mx-auto pb-20 animate-fade-in relative">
      <div ref={observerTarget} className="absolute top-0 h-1"></div>

      {/* Sticky Header Actions */}
      <div className={`sticky top-16 z-30 transition-all duration-300 ${isHeaderVisible ? 'translate-y-0' : '-translate-y-16 opacity-0 pointer-events-none'}`}>
          <div className="bg-white/95 backdrop-blur-md shadow-sm border-b border-gray-200 p-2 sm:p-3 flex flex-col gap-3">
              {/* Top Row: Search & Select */}
              <div className="flex gap-2">
                  {isSelectionMode && (
                      <div className="flex items-center gap-2 bg-gray-900 text-white px-3 rounded-xl animate-fade-in">
                          <span className="font-bold text-xs whitespace-nowrap">{selectedOrderIds.size} đã chọn</span>
                          <button onClick={handleSelectAll} className="p-1 hover:text-eco-400" title="Chọn tất cả"><i className="fas fa-check-double"></i></button>
                          <button onClick={exitSelectionMode} className="p-1 hover:text-red-400"><i className="fas fa-times"></i></button>
                      </div>
                  )}

                  <div className="relative flex-grow group">
                      <i className="fas fa-search absolute left-3 top-2.5 text-gray-400 group-focus-within:text-eco-600"></i>
                      <input 
                          value={searchTerm} 
                          onChange={e => setSearchTerm(e.target.value)} 
                          className="w-full pl-9 pr-8 py-2 bg-gray-100 border-none rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-eco-500 focus:bg-white transition-all" 
                          placeholder="Tìm khách, sđt..." 
                      />
                      <button onClick={handleVoiceSearch} className={`absolute right-2 top-2 w-6 h-6 flex items-center justify-center rounded-full hover:bg-gray-200 transition-all ${isListeningSearch ? 'text-red-500 animate-pulse' : 'text-gray-400'}`}>
                          <i className={`fas ${isListeningSearch ? 'fa-microphone-slash' : 'fa-microphone'}`}></i>
                      </button>
                  </div>

                  {/* Compact Mode Toggle */}
                  <button onClick={() => setIsCompactMode(!isCompactMode)} className={`w-9 h-9 rounded-xl flex items-center justify-center border transition-all ${isCompactMode ? 'bg-eco-50 border-eco-200 text-eco-600' : 'bg-white border-gray-200 text-gray-400'}`}>
                      <i className={`fas ${isCompactMode ? 'fa-list' : 'fa-th-large'}`}></i>
                  </button>
              </div>

              {/* Bottom Row: Filters & Bulk Actions */}
              <div className="flex justify-between items-center overflow-x-auto no-scrollbar gap-2">
                  <div className="flex gap-2 shrink-0">
                      {/* Batch Filter Dropdown */}
                      <div className="relative">
                          <button ref={batchDropdownBtnRef} onClick={() => { setActiveDropdown(activeDropdown === 'BATCH' ? null : 'BATCH'); if (batchDropdownBtnRef.current) { const rect = batchDropdownBtnRef.current.getBoundingClientRect(); setDropdownPos({ top: rect.bottom + 5, left: rect.left, width: 220 }); } }} className={`h-8 px-3 rounded-lg border flex items-center gap-2 text-[10px] font-bold uppercase transition-all ${filterBatch.length > 0 ? 'bg-orange-50 border-orange-200 text-orange-700' : 'bg-white border-gray-200 text-gray-600'}`}>
                              <i className="fas fa-box"></i> {filterBatch.length > 0 ? `${filterBatch.length} Lô` : 'Tất cả Lô'}
                          </button>
                      </div>

                      {/* Status Filter Dropdown */}
                      <div className="relative">
                          <button ref={statusDropdownBtnRef} onClick={() => { setActiveDropdown(activeDropdown === 'STATUS' ? null : 'STATUS'); if (statusDropdownBtnRef.current) { const rect = statusDropdownBtnRef.current.getBoundingClientRect(); setDropdownPos({ top: rect.bottom + 5, left: rect.left, width: 180 }); } }} className={`h-8 px-3 rounded-lg border flex items-center gap-2 text-[10px] font-bold uppercase transition-all ${filterStatus.length > 0 ? 'bg-blue-50 border-blue-200 text-blue-700' : 'bg-white border-gray-200 text-gray-600'}`}>
                              <i className="fas fa-filter"></i> {filterStatus.length > 0 ? `${filterStatus.length} Trạng thái` : 'Tất cả'}
                          </button>
                      </div>
                  </div>

                  <div className="flex gap-2 shrink-0">
                      {isSelectionMode ? (
                          <>
                              <button onClick={() => setMoveBatchData({ isOpen: true, targetBatch: '' })} className="h-8 px-3 bg-white border border-gray-200 rounded-lg text-[10px] font-black uppercase text-purple-600 hover:bg-purple-50 transition-all shadow-sm">Chuyển Lô</button>
                              <button onClick={() => setShowBulkStatusModal(true)} className="h-8 px-3 bg-white border border-gray-200 rounded-lg text-[10px] font-black uppercase text-blue-600 hover:bg-blue-50 transition-all shadow-sm">Đổi Trạng Thái</button>
                              <button onClick={() => preparePrint([])} className="h-8 px-3 bg-white border border-gray-200 rounded-lg text-[10px] font-black uppercase text-gray-700 hover:bg-gray-50 transition-all shadow-sm"><i className="fas fa-print mr-1"></i> In ({selectedOrderIds.size})</button>
                              <button onClick={handleBulkDelete} className="h-8 w-8 bg-red-50 text-red-500 rounded-lg flex items-center justify-center border border-red-100 hover:bg-red-100"><i className="fas fa-trash"></i></button>
                          </>
                      ) : (
                          <>
                              <button onClick={() => setShowRoutePlanner(true)} className="h-8 px-3 bg-indigo-50 border border-indigo-100 rounded-lg text-[10px] font-black uppercase text-indigo-600 hover:bg-indigo-100 transition-all flex items-center gap-1 shadow-sm"><i className="fas fa-route"></i> Lộ trình</button>
                              <button onClick={() => { setOrdersToPrint(filteredOrders); setShowPrintTypeModal(true); }} className="h-8 px-3 bg-gray-50 border border-gray-200 rounded-lg text-[10px] font-black uppercase text-gray-600 hover:bg-gray-100 transition-all flex items-center gap-1 shadow-sm"><i className="fas fa-print"></i> In Lô</button>
                              <button onClick={() => setShowShipperSummary(true)} className="h-8 w-8 bg-yellow-50 text-yellow-600 rounded-lg flex items-center justify-center border border-yellow-100 hover:bg-yellow-100 shadow-sm"><i className="fas fa-file-invoice-dollar"></i></button>
                          </>
                      )}
                  </div>
              </div>
          </div>
      </div>

      {/* FLOATING PORTAL DROPDOWNS */}
      {activeDropdown && (
          <div id="floating-dropdown-portal" className="fixed z-[100] bg-white rounded-xl shadow-xl border border-gray-100 p-2 animate-scale-in origin-top-left overflow-y-auto max-h-60 no-scrollbar" style={{ top: dropdownPos.top, left: dropdownPos.left, width: dropdownPos.width }}>
              {activeDropdown === 'BATCH' && (
                  <>
                      <div onClick={() => { setFilterBatch([]); setActiveDropdown(null); }} className={`p-2 rounded-lg text-[11px] font-bold cursor-pointer hover:bg-gray-50 flex items-center gap-2 ${filterBatch.length === 0 ? 'text-eco-600 bg-eco-50' : 'text-gray-600'}`}>
                          {filterBatch.length === 0 && <i className="fas fa-check"></i>} Tất cả
                      </div>
                      {uniqueBatches.map(b => (
                          <div key={b} onClick={() => { setFilterBatch(prev => prev.includes(b) ? prev.filter(x => x !== b) : [...prev, b]); }} className={`p-2 rounded-lg text-[11px] font-bold cursor-pointer hover:bg-gray-50 flex items-center gap-2 ${filterBatch.includes(b) ? 'text-orange-600 bg-orange-50' : 'text-gray-600'}`}>
                              {filterBatch.includes(b) ? <i className="fas fa-check-square"></i> : <i className="far fa-square text-gray-300"></i>} {b}
                          </div>
                      ))}
                  </>
              )}
              {activeDropdown === 'STATUS' && (
                  <>
                      {Object.values(OrderStatus).map(s => (
                          <div key={s} onClick={() => { setFilterStatus(prev => prev.includes(s) ? prev.filter(x => x !== s) : [...prev, s]); }} className={`p-2 rounded-lg text-[11px] font-bold cursor-pointer hover:bg-gray-50 flex items-center gap-2 ${filterStatus.includes(s) ? 'text-blue-600 bg-blue-50' : 'text-gray-600'}`}>
                              {filterStatus.includes(s) ? <i className="fas fa-check-square"></i> : <i className="far fa-square text-gray-300"></i>} {statusLabels[s]}
                          </div>
                      ))}
                  </>
              )}
          </div>
      )}

      {/* Main Order Grid */}
      <div 
        className={`p-2 sm:p-4 ${isCompactMode ? 'flex flex-col' : 'grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3'}`}
        onScroll={handleScroll}
      >
          {visibleOrders.map((order, idx) => {
              const customerData = customers.find(c => c.id === order.customerId || normalizePhone(c.phone) === normalizePhone(order.customerPhone));
              const isNew = !customerData && (customers.filter(c => normalizePhone(c.phone) === normalizePhone(order.customerPhone)).length === 0);

              return (
                  <OrderCard 
                      key={order.id} 
                      order={order} 
                      index={idx}
                      onUpdate={(u) => storageService.saveOrder(u)} 
                      onDelete={handleDeleteClick} 
                      onEdit={handleEdit}
                      isSortMode={sortBy === 'ROUTE'}
                      isCompactMode={isCompactMode}
                      isNewCustomer={isNew}
                      customerData={customerData}
                      onSplitBatch={handleSplitBatch}
                      onRowDragStart={handleDragStart}
                      onRowDragEnter={handleDragEnter}
                      onDragEnd={handleDragEnd}
                      isSelectionMode={isSelectionMode}
                      isSelected={selectedOrderIds.has(order.id)}
                      onToggleSelect={handleSelectOrder}
                      onLongPress={handleLongPressOrder}
                      onShowQR={handleShowQR}
                      onMoveBatch={(o) => setMoveBatchData({ isOpen: true, targetBatch: '' })}
                      onViewDetail={handleViewDetail}
                  />
              );
          })}

          {visibleOrders.length === 0 && (
              <div className="col-span-full py-20 flex flex-col items-center justify-center text-gray-300 opacity-60">
                  <i className="fas fa-box-open text-6xl mb-4"></i>
                  <span className="text-xs font-black uppercase tracking-widest">Không tìm thấy đơn hàng</span>
              </div>
          )}
      </div>

      {/* NEW: Reusable Order Edit Modal */}
      {editingOrder && (
          <OrderEditModal 
              isOpen={!!editingOrder} 
              onClose={() => setEditingOrder(null)} 
              order={editingOrder} 
              products={products}
              onSave={() => setEditingOrder(null)} 
          />
      )}

      {/* QR MODAL */}
      {qrState.isOpen && qrState.order && (
          <div className="fixed inset-0 z-[120] bg-gray-900/80 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in" onClick={() => setQrState({ isOpen: false, url: '', order: null })}>
              <div className="bg-white rounded-[2.5rem] shadow-2xl p-8 max-w-sm w-full text-center relative overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-blue-500 via-purple-500 to-pink-500"></div>
                  <h3 className="text-xl font-black text-gray-900 uppercase italic tracking-tighter mb-1">Quét mã thanh toán</h3>
                  <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-6">Đơn hàng #{qrState.order.id}</p>

                  <div className="bg-white p-4 rounded-3xl shadow-[0_10px_40px_-10px_rgba(0,0,0,0.1)] border-2 border-gray-100 mb-6 inline-block relative group">
                      {qrState.url ? (
                          <img src={qrState.url} alt="QR Code" className="w-48 h-48 object-contain rounded-xl" />
                      ) : (
                          <div className="w-48 h-48 bg-gray-100 rounded-xl flex items-center justify-center animate-pulse"><i className="fas fa-qrcode text-4xl text-gray-300"></i></div>
                      )}
                      <div className="absolute -bottom-3 -right-3 w-10 h-10 bg-green-500 rounded-full border-4 border-white flex items-center justify-center text-white shadow-lg">
                          <i className="fas fa-check"></i>
                      </div>
                  </div>

                  <div className="text-3xl font-black text-gray-900 tracking-tighter mb-6">
                      {new Intl.NumberFormat('vi-VN').format(qrState.order.totalPrice)}<span className="text-lg align-top text-gray-400 ml-1">đ</span>
                  </div>

                  <div className="flex gap-3">
                      <button onClick={() => setQrState({ isOpen: false, url: '', order: null })} className="flex-1 py-3 bg-gray-100 text-gray-600 rounded-xl font-bold text-xs uppercase hover:bg-gray-200 transition-all">Đóng</button>
                      <button onClick={handleShareQR} className="flex-1 py-3 bg-black text-white rounded-xl font-bold text-xs uppercase shadow-lg hover:bg-gray-800 transition-all flex items-center justify-center gap-2"><i className="fas fa-share-alt"></i> Chia sẻ</button>
                  </div>
              </div>
          </div>
      )}

      {/* DETAIL MODAL (COMPACT MODE) */}
      {detailOrder && (
          <div className="fixed inset-0 z-[110] bg-gray-900/60 backdrop-blur-sm flex items-end sm:items-center justify-center animate-fade-in" onClick={() => setDetailOrder(null)}>
              <div className="bg-white w-full sm:max-w-md sm:rounded-[2rem] rounded-t-[2rem] shadow-2xl max-h-[85vh] overflow-y-auto animate-slide-up" onClick={e => e.stopPropagation()}>
                  <div className="p-6">
                      <div className="flex justify-between items-start mb-4">
                          <div>
                              <h3 className="text-xl font-black text-gray-900 uppercase leading-tight">{detailOrder.customerName}</h3>
                              <div className="flex items-center gap-2 mt-1">
                                  <span className="bg-gray-100 px-2 py-0.5 rounded text-[10px] font-mono font-bold text-gray-600">{detailOrder.customerPhone}</span>
                                  <span className="bg-blue-50 px-2 py-0.5 rounded text-[10px] font-bold text-blue-600 uppercase">{detailOrder.batchId}</span>
                              </div>
                          </div>
                          <button onClick={() => setDetailOrder(null)} className="w-8 h-8 rounded-full bg-gray-50 flex items-center justify-center text-gray-400"><i className="fas fa-times"></i></button>
                      </div>

                      <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100 mb-4">
                          <p className="text-xs font-bold text-gray-700 leading-relaxed">
                              {detailOrder.items[0] && customers.find(c => c.id === detailOrder.customerId)?.isAddressVerified && <i className="fas fa-check-circle text-green-500 mr-1" title="Đã xác thực vị trí"></i>}
                              <i className="fas fa-map-marker-alt text-red-500 mr-2"></i>{detailOrder.address}
                          </p>
                          {detailOrder.notes && <p className="text-xs font-medium text-orange-600 mt-2 pt-2 border-t border-gray-200"><i className="fas fa-sticky-note mr-2"></i>{detailOrder.notes}</p>}
                      </div>

                      <div className="space-y-3 mb-6">
                          {detailOrder.items.map((item, idx) => (
                              <div key={idx} className="flex justify-between items-center py-2 border-b border-dashed border-gray-100">
                                  <div className="flex items-center gap-3">
                                      <div className="w-6 h-6 bg-gray-100 rounded flex items-center justify-center text-[10px] font-black text-gray-500">{item.quantity}</div>
                                      <span className="text-sm font-bold text-gray-800">{item.name}</span>
                                  </div>
                                  <span className="text-sm font-bold text-gray-900">{new Intl.NumberFormat('vi-VN').format(item.price * item.quantity)}</span>
                              </div>
                          ))}
                          <div className="flex justify-between items-center pt-2">
                              <span className="text-xs font-black text-gray-400 uppercase tracking-widest">Tổng cộng</span>
                              <span className="text-2xl font-black text-eco-600">{new Intl.NumberFormat('vi-VN').format(detailOrder.totalPrice)}đ</span>
                          </div>
                      </div>

                      <div className="grid grid-cols-2 gap-3">
                          <button onClick={() => handleEdit(detailOrder)} className="py-3 bg-gray-100 text-gray-700 rounded-xl font-bold text-xs uppercase hover:bg-gray-200">Chỉnh sửa</button>
                          <button onClick={() => handleSplitBatch(detailOrder)} className="py-3 bg-orange-100 text-orange-700 rounded-xl font-bold text-xs uppercase hover:bg-orange-200">Hoãn giao</button>
                          <button onClick={() => handleShowQR(detailOrder)} className="py-3 bg-blue-100 text-blue-700 rounded-xl font-bold text-xs uppercase hover:bg-blue-200 col-span-2">Lấy mã QR</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* OTHER MODALS */}
      <ConfirmModal isOpen={showDeleteConfirm} title="Xóa đơn hàng?" message="Hành động này không thể hoàn tác. Tồn kho sẽ được cộng lại." onConfirm={confirmDelete} onCancel={() => setShowDeleteConfirm(false)} confirmLabel="Xóa vĩnh viễn" isDanger={true} />
      <ConfirmModal isOpen={showBulkDeleteConfirm} title={`Xóa ${selectedOrderIds.size} đơn hàng?`} message="Các đơn hàng đã chọn sẽ bị xóa vĩnh viễn." onConfirm={confirmBulkDelete} onCancel={() => setShowBulkDeleteConfirm(false)} confirmLabel="Xóa hết" isDanger={true} />
      <ConfirmModal isOpen={showBulkStatusModal} title="Cập nhật trạng thái?" message={`Thay đổi trạng thái cho ${selectedOrderIds.size} đơn hàng đã chọn.`} onConfirm={() => {}} onCancel={() => setShowBulkStatusModal(false)} confirmLabel="Cập nhật" />
      {showBulkStatusModal && (
          <div className="fixed inset-0 z-[120] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-2xl p-5 w-full max-w-xs shadow-2xl">
                  <h3 className="font-black text-gray-800 uppercase mb-4 text-center">Chọn trạng thái mới</h3>
                  <div className="space-y-2">
                      {Object.values(OrderStatus).map(s => (
                          <button key={s} onClick={() => handleBulkStatusChange(s)} className="w-full py-3 bg-gray-50 hover:bg-gray-100 rounded-xl font-bold text-xs text-gray-700 uppercase transition-colors">{statusLabels[s]}</button>
                      ))}
                  </div>
                  <button onClick={() => setShowBulkStatusModal(false)} className="w-full mt-4 py-2 text-gray-400 font-bold text-xs hover:text-gray-600">Hủy bỏ</button>
              </div>
          </div>
      )}

      {/* Move Batch Modal */}
      {moveBatchData.isOpen && (
          <div className="fixed inset-0 z-[120] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-2xl p-5 w-full max-w-xs shadow-2xl">
                  <h3 className="font-black text-gray-800 uppercase mb-4 text-center">Chuyển sang lô nào?</h3>
                  <div className="max-h-60 overflow-y-auto space-y-2 no-scrollbar">
                      {uniqueBatches.map(b => (
                          <button key={b} onClick={() => setMoveBatchData({ ...moveBatchData, targetBatch: b })} className={`w-full py-3 rounded-xl font-bold text-xs uppercase transition-colors ${moveBatchData.targetBatch === b ? 'bg-purple-600 text-white' : 'bg-gray-50 text-gray-700 hover:bg-gray-100'}`}>{b}</button>
                      ))}
                      <div className="pt-2 border-t border-gray-100">
                          <input placeholder="Hoặc nhập tên lô mới..." className="w-full p-2 bg-white border-2 border-gray-200 rounded-lg text-xs font-bold outline-none focus:border-purple-500 uppercase" onChange={(e) => setMoveBatchData({...moveBatchData, targetBatch: e.target.value})} />
                      </div>
                  </div>
                  <div className="flex gap-2 mt-4">
                      <button onClick={() => setMoveBatchData({ isOpen: false, targetBatch: '' })} className="flex-1 py-2 bg-gray-100 rounded-lg font-bold text-xs text-gray-500">Hủy</button>
                      <button onClick={handleMoveBatch} disabled={!moveBatchData.targetBatch} className="flex-1 py-2 bg-purple-600 text-white rounded-lg font-bold text-xs shadow-md disabled:bg-gray-300">Chuyển</button>
                  </div>
              </div>
          </div>
      )}

      {/* PRINT TYPE MODAL */}
      {showPrintTypeModal && (
          <div className="fixed inset-0 z-[120] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-[2rem] p-6 w-full max-w-sm shadow-2xl text-center">
                  <h3 className="font-black text-xl text-gray-900 uppercase italic tracking-tighter mb-2">Chọn mẫu in</h3>
                  <p className="text-xs font-bold text-gray-400 mb-6">Bạn muốn in {ordersToPrint.length > 0 ? ordersToPrint.length : selectedOrderIds.size} đơn hàng theo kiểu nào?</p>

                  <div className="grid grid-cols-2 gap-4">
                      <button onClick={handlePrintBatch} disabled={isPrinting} className="bg-gray-50 border-2 border-gray-200 hover:border-gray-900 rounded-2xl p-4 flex flex-col items-center gap-3 transition-all group">
                          <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-2xl shadow-sm group-hover:scale-110 transition-transform">🏷️</div>
                          <span className="font-black text-xs uppercase text-gray-700">Tem dán<br/>(8 tem/A4)</span>
                      </button>
                      <button onClick={handlePrintCompact} disabled={isPrinting} className="bg-gray-50 border-2 border-gray-200 hover:border-gray-900 rounded-2xl p-4 flex flex-col items-center gap-3 transition-all group">
                          <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-2xl shadow-sm group-hover:scale-110 transition-transform">📋</div>
                          <span className="font-black text-xs uppercase text-gray-700">Danh sách<br/>(Manifest)</span>
                      </button>
                  </div>

                  {isPrinting && (
                      <div className="mt-6">
                          <div className="w-full bg-gray-100 rounded-full h-2 overflow-hidden">
                              <div className="bg-eco-500 h-full transition-all duration-300" style={{ width: `${printProgress}%` }}></div>
                          </div>
                          <p className="text-[10px] font-bold text-eco-600 mt-2 uppercase tracking-widest">Đang xử lý PDF... {printProgress}%</p>
                      </div>
                  )}

                  {!isPrinting && <button onClick={() => setShowPrintTypeModal(false)} className="mt-6 text-xs font-bold text-gray-400 hover:text-gray-600">Đóng lại</button>}
              </div>
          </div>
      )}

      {/* Global Product Modals */}
      <ProductEditModal 
        isOpen={!!editingProduct || editProductMode === 'IMPORT' && !!editingProduct} 
        onClose={() => { setEditingProduct(null); setShowProductModal(false); }} 
        product={editingProduct} 
        onSave={handleSaveProduct} 
        initialMode={editProductMode} 
        allProducts={products}
        onSwitchToProduct={(p) => { setEditingProduct(p); setEditProductMode('SET'); }}
      />
      <ConfirmModal 
          isOpen={showSyncConfirm} 
          title="Đồng bộ đơn hàng?" 
          message="Bạn có muốn cập nhật thông tin mới (Giá/Tên) cho các đơn hàng CHỜ XỬ LÝ không?" 
          onConfirm={handleConfirmSync} 
          onCancel={() => { setShowSyncConfirm(false); setPendingProductUpdate(null); }}
          confirmLabel="Đồng bộ ngay"
          cancelLabel="Chỉ sửa kho"
      />

      <RoutePlannerModal isOpen={showRoutePlanner} onClose={() => setShowRoutePlanner(false)} orders={filteredOrders} onApplySort={handleApplySort} />
      <ShipperSummaryModal isOpen={showShipperSummary} onClose={() => setShowShipperSummary(false)} orders={filteredOrders} batchName={filterBatch.join('+') || 'Tất cả'} />
    </div>
  );
};

export default TrackingDashboard;
